import type { SectionType } from './types'

const articles: Record<string, SectionType[]> = {

'great-migration-guide': [
  { type: 'p', text: 'Cada año, más de 1,5 millones de ñus, 500.000 cebras y 200.000 gacelas de Thomson recorren un enorme circuito por el ecosistema Serengueti-Mara, impulsados únicamente por la lluvia, la hierba y un instinto ancestral de supervivencia. No hay un único día en que comience la migración. No hay una ruta establecida. Es un movimiento continuo, caótico y fascinante que nunca se detiene del todo, y entender su ritmo es la clave para presenciarlo en su momento más dramático.' },
  { type: 'h2', text: '¿Qué es la Gran Migración?' },
  { type: 'p', text: 'La Gran Migración de Ñus es el mayor movimiento de animales terrestres de la Tierra. Sigue una ruta circular entre el Serengueti en Tanzania y el Masái Mara en Kenia, un viaje de aproximadamente 1.200 kilómetros impulsado por las lluvias estacionales. Los ñus no siguen a un líder: siguen la hierba. A medida que las lluvias impulsan el crecimiento fresco por distintas partes del ecosistema, las manadas se desplazan en consecuencia, creando un espectáculo en constante evolución que se despliega a lo largo de los doce meses del año.' },
  { type: 'p', text: "El término 'temporada de migración' es engañoso. La migración dura todo el año. Lo que cambia es la ubicación de las manadas y la naturaleza del drama que se ofrece. En enero se contempla el nacimiento de decenas de miles de crías en las llanuras del sur. En julio y agosto las manadas se agolpan a orillas del río Mara, desencadenando algunos de los momentos más fotografiados de la historia de la vida salvaje. Cada mes ofrece algo extraordinario, si sabes dónde buscar." },
  { type: 'h2', text: 'Calendario mensual de la migración' },
  { type: 'table', headers: ['Mes', 'Ubicación', 'Espectáculo principal'], rows: [
    ['Enero', 'Serengueti sur (Ndutu)', 'Temporada de partos: miles de crías nacen cada día'],
    ['Febrero', 'Serengueti sur (Ndutu)', 'Pico de partos; actividad de depredadores muy alta'],
    ['Marzo', 'Serengueti sur y central', 'Las manadas comienzan a moverse al norte al aflojar las lluvias'],
    ['Abril', 'Serengueti central', 'Lluvias largas; manadas dispersas por las llanuras centrales'],
    ['Mayo', 'Serengueti central y occidental', 'Las manadas se concentran; cielos de tormenta dramáticos'],
    ['Junio', 'Corredor occidental (Grumeti)', 'Cruces del río Grumeti; enormes cocodrilos'],
    ['Julio', 'Serengueti norte y Masái Mara', 'Comienzan los cruces del río Mara; drama máximo'],
    ['Agosto', 'Serengueti norte y Masái Mara', 'Mayor densidad de cruces del río Mara'],
    ['Septiembre', 'Masái Mara (Kenia)', 'Manadas en Kenia; excelente avistamiento de fauna'],
    ['Octubre', 'Serengueti norte', 'Las manadas regresan al sur; cruces inversos del Mara'],
    ['Noviembre', 'Serengueti central', 'Lluvias cortas; manadas se dirigen al sur'],
    ['Diciembre', 'Serengueti sur (Ndutu)', 'Las manadas llegan a los campos de parto'],
  ]},
  { type: 'p', text: 'La tabla anterior muestra el patrón general, pero los patrones de lluvias varían de año en año. Las manadas pueden ir dos o cuatro semanas por delante o por detrás de lo previsto dependiendo de cuándo lleguen las lluvias. Por eso trabajar con un operador local que rastree las manadas en tiempo real marca una enorme diferencia en tu experiencia.' },
  { type: 'h2', text: 'Los cruces del río Mara' },
  { type: 'p', text: 'Nada en el mundo natural se puede comparar con ver a los ñus lanzarse al río Mara. Decenas de miles de animales se agolpan en la orilla, empujando hacia adelante con el peso de la manada detrás de ellos. El agua hierve. Enormes cocodrilos del Nilo, algunos de más de tres metros de largo, esperan en las aguas poco profundas. Y entonces, en un momento que parece a la vez inevitable e imposible, el animal cabecero salta y comienza el cruce.' },
  { type: 'p', text: 'Los cruces se producen en varios puntos a lo largo del río Mara, principalmente en el norte del Serengueti y en el Masái Mara. Los cruces más espectaculares tienden a ocurrir en puntos conocidos por los guías locales: determinadas curvas del río donde las orillas son lo suficientemente empinadas como para concentrar a los animales. Un solo cruce puede implicar a 10.000 ñus y durar varias horas. Después las manadas se retiran, se reagrupan y pueden intentar el mismo cruce al día siguiente.' },
  { type: 'p', text: 'Los cruces son impredecibles. Las manadas pueden esperar días antes de cruzar y luego cruzar varias veces en una sola mañana. Aquí es donde más importa la calidad de tu guía. Un gran guía lee el comportamiento de la manada —la concentración, el círculo, los líderes explorando la orilla— y coloca el vehículo donde se desarrollará la acción. Un guía mediocre espera a que haya muchos vehículos. Reserva con una empresa cuyos guías hayan pasado temporadas en el norte del Serengueti y conozcan íntimamente estas curvas del río.' },
  { type: 'tip', title: 'Consejo profesional: la posición importa', text: 'Los mejores puntos de observación de los cruces del río Mara requieren llegar temprano y tener paciencia. Los guías que llevan a los clientes de un cruce a otro a toda prisa suelen perderse los mejores momentos. Planea pasar al menos media jornada en un solo lugar: la espera casi siempre tiene recompensa.' },
  { type: 'h2', text: 'La temporada de partos: el espectáculo subestimado' },
  { type: 'p', text: 'Enero y febrero en el sur del Serengueti, especialmente en la zona de Ndutu, ofrecen lo que muchos viajeros con experiencia en safari consideran la mejor experiencia de fauna salvaje de África. Hasta 8.000 crías de ñu nacen cada día en el pico de la temporada de partos. Las llanuras se vuelven doradas y parecen vibrar de vida. Guepardos, leones, leopardos, hienas y perros salvajes convergen en la zona, atraídos por la abundancia de presas.' },
  { type: 'p', text: 'La temporada de partos es menos famosa que los cruces del río, pero mucho más accesible. Los precios son más bajos, hay menos gente y la densidad de interacciones depredador-presa es extraordinaria. Una sola mañana de conducción en la temporada de partos puede ofrecer una caza de guepardo, una manada de leones sobre una presa y una cría recién nacida dando sus primeros pasos, todo antes del desayuno. Si solo puedes visitar Tanzania una vez, enero y febrero en la zona de Ndutu merecen una consideración seria.' },
  { type: 'h2', text: 'Dónde alojarse para la mejor experiencia de migración' },
  { type: 'p', text: 'El alojamiento para la migración cae en dos grandes categorías: campamentos móviles que siguen a las manadas y alojamientos permanentes en ubicaciones fijas. Los campamentos móviles —los que se mueven estacionalmente para permanecer cerca de la acción— ofrecen la experiencia de migración más consistentemente excelente porque el campamento siempre está cerca de las manadas. Tienden a ser más pequeños, más íntimos y situados en zonas donde no se permiten alojamientos permanentes.' },
  { type: 'p', text: 'Los alojamientos permanentes en el norte del Serengueti son excelentes de julio a octubre, cuando las manadas están predeciblemente en el norte. Los alojamientos de la zona de Ndutu son la mejor opción para la temporada de partos en enero y febrero. La clave es adaptar el alojamiento al calendario de la migración: un alojamiento en el Serengueti central no te dará la misma experiencia que uno situado en el camino de las manadas.' },
  { type: 'ul', items: [
    'Alojamientos del Serengueti central: ideales de marzo a mayo cuando las manadas pasan por aquí',
    'Campamentos del corredor occidental: ideales en junio cuando se producen los cruces del Grumeti',
    'Campamentos del Serengueti norte: ideales de julio a octubre durante la temporada de cruces del Mara',
    'Campamentos de la zona de Ndutu: ideales de enero a febrero en la temporada de partos',
  ]},
  { type: 'h2', text: '¿Con cuánta antelación debes reservar?' },
  { type: 'p', text: 'Para el período de cruces del río Mara de julio a septiembre, los mejores campamentos se llenan entre 12 y 18 meses de antelación. Esto no es una exageración: los campamentos móviles y semipermanentes más codiciados del norte del Serengueti están completamente reservados en octubre del año anterior. Si quieres presenciar los cruces desde un campamento de calidad y no desde un alojamiento de bajo presupuesto abarrotado, empieza a planificar con al menos un año de antelación.' },
  { type: 'p', text: 'Para la temporada de partos (enero-febrero) y los meses de transición, tienes más flexibilidad: seis meses de antelación suelen ser suficientes para encontrar un buen alojamiento. Dicho esto, los campamentos de alta calidad específicos se llenan rápidamente independientemente de la temporada. Cuanto antes reserves, más opciones tendrás.' },
  { type: 'callout', text: 'La Gran Migración no es un espectáculo garantizado en ningún día concreto. Recompensa la paciencia, los buenos guías y los itinerarios flexibles. Reserva con una empresa que monitorice los movimientos de las manadas en tiempo real y pueda adaptar tus excursiones en consecuencia: esa flexibilidad vale más que cualquier nombre de campamento concreto.' },
  { type: 'h2', text: 'Consejos prácticos para safaris de migración' },
  { type: 'ul', items: [
    'Lleva una cámara con al menos un objetivo de 400 mm si quieres fotos de fauna de primer plano desde el vehículo',
    'Viste colores neutros (caqui, oliva, beige): evita el blanco y los colores brillantes en el vehículo',
    'Empieza las excursiones al amanecer: la mejor actividad de depredadores ocurre en las primeras dos horas del día',
    'Reserva tiempo para una jornada completa en los puntos de cruce del río, no solo dos horas',
    'Pide a tu operador actualizaciones en tiempo real sobre la ubicación de las manadas en la semana antes de viajar',
    'Lleva unos buenos prismáticos: 8×42 es la ampliación ideal para safari',
    'Permite al menos cuatro o cinco días en el Serengueti para tener la mejor oportunidad de presenciar un cruce',
  ]},
  { type: 'h2', text: 'Cómo llegar' },
  { type: 'p', text: 'La principal puerta de entrada al Serengueti es el Aeropuerto Internacional de Kilimanjaro (JRO), cerca de Arusha, o el Aeropuerto Internacional Julius Nyerere (DAR) en Dar es Salaam. Desde Arusha, puedes llegar al sur del Serengueti en aproximadamente seis o siete horas en coche, o volar en 45-60 minutos a una de las varias pistas de aterrizaje. Para la mayoría de los itinerarios de migración, volar entre parques ahorra tiempo y ofrece una extraordinaria vista aérea del ecosistema de abajo: las manadas de ñus parecen ríos oscuros fluyendo por las doradas llanuras.' },
  { type: 'p', text: 'El circuito norte más eficiente combina el Serengueti con el Cráter del Ngorongoro y el Parque Nacional Tarangire: tres ecosistemas distintos que se complementan perfectamente entre sí. Una semana en Tanzania construida alrededor de este circuito, sincronizada con el calendario de la migración, es una de las mejores experiencias de fauna salvaje disponibles en cualquier parte del mundo.' },
],

'tanzania-safari-cost': [
  { type: 'p', text: 'El rango de precios de un safari en Tanzania es asombroso. Puedes gastar 150 dólares por persona y día acampando en Tarangire, o 1.500 dólares por persona y día en una concesión privada exclusiva en el Serengueti, y ambas son experiencias genuinas de safari en Tanzania. Entender qué impulsa el coste y qué obtienes en cada rango de precios es el paso más importante para planificar un viaje que se ajuste a tus expectativas y a tu presupuesto.' },
  { type: 'h2', text: 'Los grandes factores de coste' },
  { type: 'p', text: 'Las tarifas de los parques nacionales de Tanzania son innegociables y las fija el gobierno tanzano. Para el Serengueti, actualmente se pagan 82 dólares por persona y día solo por la entrada al parque, más una tarifa separada para el vehículo. En el Área de Conservación del Ngorongoro, hay una tarifa adicional de servicio del cráter además de la tarifa de la zona de conservación. Estas tarifas gubernamentales se aplican a todos los visitantes independientemente del alojamiento u operador que utilicen, y constituyen una parte significativa de tu coste diario por persona.' },
  { type: 'p', text: 'El alojamiento es la variable más grande de tu presupuesto. La diferencia entre un safari de acampada económico y un alojamiento de lujo no está principalmente en la fauna, sino en la cama, el baño, la comida y el vehículo. Un safari de acampada económico significa compartir una tienda comedor con otros viajeros y dormir en una tienda básica. Un alojamiento de gama media te da una habitación con baño, agua caliente y piscina. Un campamento de lujo te ofrece una suite privada, un mayordomo personal, un vehículo privado y excursiones exclusivas.' },
  { type: 'h2', text: 'Coste del safari en Tanzania por nivel de presupuesto' },
  { type: 'table', headers: ['Nivel de presupuesto', 'Coste por persona y día', 'Qué incluye'], rows: [
    ['Económico', '150-250 $', 'Safari de acampada, vehículo compartido (6-8 personas), comidas básicas, parques estándar'],
    ['Gama media', '250-450 $', 'Alojamiento en tienda o hotel de gama media, vehículo compartido (4-6 personas), buena comida'],
    ['Gama media alta', '450-700 $', 'Campamentos de calidad, vehículos más pequeños, guía privado posible'],
    ['Lujo', '700-1.200 $', 'Alojamientos premium, vehículo privado, guías expertos, zonas exclusivas'],
    ['Ultra lujo', '1.200 $ +', 'Concesiones privadas, campamento totalmente privado, itinerario a medida, traslados aéreos'],
  ]},
  { type: 'p', text: 'Estas cifras son por persona y día e incluyen alojamiento, comidas, tasas de parque y excursiones. No incluyen los vuelos internacionales a Tanzania, las tasas de visado (50 dólares para la mayoría de las nacionalidades), las propinas para guías y personal del campamento (calcula entre 10 y 20 dólares por persona y día para guías, y de 5 a 10 para el personal del campamento) ni las compras personales.' },
  { type: 'h2', text: 'Desglose de las tasas gubernamentales de los parques' },
  { type: 'p', text: 'Las tasas de los parques de Tanzania son de las más altas de África, y van directamente a la Autoridad de Parques Nacionales de Tanzania (TANAPA) para la conservación. Para los parques más populares, la estructura de tasas actual es la siguiente: el Parque Nacional del Serengueti cobra 82 dólares por adulto y día. El Área de Conservación del Ngorongoro cobra 80 dólares por adulto y día más una tarifa de servicio del cráter de 300 dólares por vehículo para el descenso al cráter. El Parque Nacional Tarangire cobra 55 dólares por adulto y día. El Lago Manyara cobra 45 dólares por adulto y día.' },
  { type: 'p', text: 'Las tarifas de los vehículos añaden otros 40-60 dólares por vehículo, parque y día. Un vehículo 4×4 estándar para safari compartido entre cuatro viajeros supone que la tarifa del vehículo añade entre 10 y 15 dólares por persona y día a tu coste. Los vehículos privados, en los que debes insistir a partir de la gama media alta, tienen la misma tarifa pero la paga íntegramente tu grupo, lo que hace que el coste por persona sea mayor pero la experiencia muy superior.' },
  { type: 'tip', title: 'Ahorro en temporada verde', text: 'Visitar durante las lluvias largas (abril-mayo) y las lluvias cortas (noviembre) puede reducir las tarifas de los alojamientos entre un 20 y un 40 %. La fauna sigue siendo excelente, el paisaje es exuberante y fotogénico, y compartes los parques con muchos menos vehículos. La temporada verde es uno de los secretos mejor guardados en el precio de los safaris en Tanzania.' },
  { type: 'h2', text: '¿Cuánto cuesta realmente un safari de 7 días en Tanzania?' },
  { type: 'p', text: 'Un safari de 7 noches por el Circuito Norte (Tarangire, Manyara, Serengueti, Ngorongoro) para dos personas compartiendo, viajando en nivel de gama media con vehículo y guía privados, costará normalmente entre 4.500 y 6.500 dólares por persona con todo incluido en destino. Esto incluye todas las tasas de los parques, alojamiento, comidas, excursiones y traslados al aeropuerto. Los vuelos internacionales desde Europa o EE. UU. añaden entre 800 y 1.800 dólares por persona según la ciudad de salida y el momento de la reserva.' },
  { type: 'p', text: 'En el nivel económico, el mismo itinerario de 7 noches en un safari de acampada con vehículos compartidos cuesta normalmente entre 1.800 y 2.800 dólares por persona en destino. Los parques visitados son idénticos y la experiencia de fauna es comparable, pero el nivel de comodidad entre excursiones es significativamente diferente. Los viajeros con presupuesto ajustado suelen descubrir que la propia experiencia de la excursión es tan buena como en el segmento de lujo, y usan el ahorro para pasar más noches en el campo.' },
  { type: 'p', text: 'En el extremo del lujo, un itinerario de 7 noches en campamentos exclusivos con vehículos privados, guías expertos y conexiones en avioneta entre parques cuesta entre 8.000 y 15.000 dólares o más por persona. La prima te compra privacidad, exclusividad y el tipo de logística sin contratiempos que te permite centrarte completamente en la fauna. Para muchos viajeros, la experiencia de lujo es un capricho único en la vida; para otros, se convierte en la única forma en que quieren viajar.' },
  { type: 'h2', text: 'Costes ocultos que debes conocer' },
  { type: 'ul', items: [
    'Las propinas para guías (10-20 $ por persona y día) y el personal del campamento (5-10 $ por persona y día) son estándar y esperadas',
    'Los visados cuestan 50 $ para la mayoría de las nacionalidades: solicítalos en línea en evisa.immigration.go.tz antes del viaje',
    'Certificado de vacunación contra la fiebre amarilla obligatorio si llegas desde una zona con esta enfermedad',
    'Profilaxis contra la malaria (30-80 $ por tratamiento): consulta con tu médico o clínica de viajes',
    'El seguro de viaje con cobertura de evacuación médica es esencial: calcula entre 150 y 300 dólares por persona',
    'Los permisos opcionales para el trekking de gorilas o chimpancés (700 y 100 dólares respectivamente) si añades Ruanda o Mahale',
    'El alojamiento y las actividades en la extensión de playa de Zanzíbar normalmente no están incluidos en el precio del safari',
  ]},
  { type: 'h2', text: 'Cómo obtener el mejor valor' },
  { type: 'p', text: 'El mayor factor de valor en los precios de los safaris en Tanzania es viajar con un operador local con base en Tanzania en lugar de reservar a través de un agente de viajes extranjero. Los operadores locales eliminan el recargo del 15 al 30 % que añaden los agentes extranjeros para cubrir sus propios márgenes. También obtienes una relación más directa con las personas que gestionan tu itinerario, respuestas más rápidas cuando los planes necesitan cambiar y guías que viven en la zona y conocen los parques íntimamente.' },
  { type: 'p', text: 'Compartir un vehículo con otros viajeros reduce significativamente los costes por persona sin afectar de manera significativa a la experiencia de fauna. Un grupo de cuatro personas que comparten un 4×4 cuesta aproximadamente la mitad de lo que cuesta un vehículo privado por persona. Para los viajeros económicos y de gama media, unirse a un safari en grupo pequeño (de cuatro a seis personas) es una excelente manera de acceder a itinerarios de calidad a precios más bajos.' },
  { type: 'p', text: 'Viajar en temporada de hombro —en particular junio, noviembre y principios de diciembre— te da una calidad de fauna casi de temporada alta a precios un 15-25 % más bajos que las tarifas pico. Junio es especialmente bueno: la estación seca acaba de comenzar, los cruces del río Grumeti están en marcha y los parques están notablemente menos abarrotados que en julio y agosto.' },
  { type: 'callout', text: 'Un safari en Tanzania no es barato, y no debería serlo. Las tasas de los parques financian la conservación, los salarios pagan a los guías de base comunitaria y el coste de llegar a una naturaleza remota en un 4×4 bien mantenido es genuinamente alto. Lo que compras es uno de los últimos lugares verdaderamente salvajes de la Tierra. La relación calidad-precio aquí se mide en una divisa completamente diferente a la de unas vacaciones en la playa.' },
  { type: 'h2', text: '¿Vale Tanzania lo que cuesta?' },
  { type: 'p', text: 'Todos los guías de safari y los viajeros frecuentes a África que conocemos responden a esta pregunta de la misma manera: Tanzania ofrece la experiencia de safari más consistente, más espectacular y más auténtica de África. El Serengueti solo justifica el coste. La temporada de partos en Ndutu, los cruces del río Mara, el vasto silencio de Ruaha, el paisaje volcánico del Ngorongoro: estas no son experiencias que puedas replicar en ningún otro lugar del mundo.' },
  { type: 'p', text: 'Si te preguntas si Tanzania vale la inversión, la pregunta más útil es: ¿qué nivel de comodidad necesitas para disfrutarla plenamente? En todos los niveles de presupuesto, la fauna es extraordinaria. El dinero que gastas por encima del nivel económico te compra comodidad, privacidad y experiencia, no una experiencia de fauna fundamentalmente diferente. Decide qué es lo que más te importa, ajusta tu presupuesto a esa prioridad y reserva con un operador local de confianza. Tanzania hará el resto.' },
],

'best-time-to-visit-serengeti': [
  { type: 'p', text: 'La respuesta corta es: cualquier mes. El Serengueti es uno de esos raros lugares donde la fauna es extraordinaria en todas las estaciones. La respuesta más larga es que cada mes ofrece experiencias completamente distintas, y conocer lo que cada uno ofrece te permite elegir la visita que se ajuste a tus intereses específicos, ya sea la acción de los depredadores, los cruces del río, las llanuras de parto o simplemente evitar las multitudes.' },
  { type: 'h2', text: 'Comprendiendo las estaciones del Serengueti' },
  { type: 'p', text: 'Tanzania tiene dos estaciones lluviosas: las lluvias largas de marzo a mayo y las lluvias cortas en noviembre. Entre ellas hay dos estaciones secas: la estación seca principal de junio a octubre y una época seca más corta en enero y febrero. Estos patrones de lluvia determinan dónde crece la hierba, lo que determina dónde se concentran las manadas de ñus, lo que a su vez impulsa la distribución de los depredadores. Comprender este ciclo es la clave para planificar tu visita.' },
  { type: 'p', text: 'El Serengueti cubre 14.763 kilómetros cuadrados, un área más grande que Irlanda del Norte, y las distintas zonas dentro de él albergan diferentes fases de la migración en diferentes momentos del año. Las llanuras del sur cerca de Ndutu acogen a las manadas de parto de diciembre a marzo. El Serengueti central alberga a las manadas a medida que se desplazan al norte de abril a junio. El corredor occidental ve los cruces del río Grumeti en junio. El norte del Serengueti, cerca del río Mara, es el escenario de los famosos cruces de julio a octubre.' },
  { type: 'h2', text: 'Desglose mes a mes' },
  { type: 'h3', text: 'Enero y febrero: temporada de partos' },
  { type: 'p', text: 'Enero y febrero son dos de los mejores meses para visitar el Serengueti. Las lluvias cortas han terminado y las llanuras del sur cerca de Ndutu están alfombradas de hierba verde fresca que atrae a las manadas de ñus en cientos de miles. Esta es la temporada de partos: la mayor concentración de interacciones entre depredadores y presas de África. Hasta 8.000 crías nacen cada día en el pico, y los depredadores —leones, guepardos, hienas, leopardos, perros salvajes— llegan para aprovechar el festín. Los precios son relativamente bajos, las lluvias han terminado y la vida aviaria alcanza su máximo gracias a la presencia de especies migratorias procedentes de Europa y Asia.' },
  { type: 'h3', text: 'Marzo a mayo: temporada verde' },
  { type: 'p', text: 'Las lluvias largas llegan en marzo, trayendo una transformación asombrosa al Serengueti. La hierba se vuelve verde intenso, florecen las flores silvestres, el cielo se llena de dramáticas nubes de tormenta y el paisaje parece completamente diferente de las fotos de la estación seca que probablemente hayas visto. Las manadas de ñus comienzan a moverse al norte cuando las lluvias del sur aflojan, y el Serengueti central se llena de animales. Las tarifas de los alojamientos bajan un 20-40 %, muchos campamentos cierran por mantenimiento y los parques están significativamente menos concurridos. Los avistamientos de fauna siguen siendo excelentes: de hecho, algunos safaris experimentados prefieren marzo a mayo por las oportunidades fotográficas y la soledad.' },
  { type: 'h3', text: 'Junio: transición y cruces del Grumeti' },
  { type: 'p', text: 'Junio marca el comienzo de la estación seca principal y la llegada de las manadas al corredor occidental. El río Grumeti, hogar de una población de enormes y antiguos cocodrilos del Nilo, presencia sus propios cruces dramáticos en junio, que a menudo se pasan por alto en favor del más famoso río Mara. La hierba se seca y los animales comienzan a concentrarse alrededor de las fuentes de agua, haciendo que los avistamientos de fauna sean cada vez más fiables. Los precios son más bajos que en julio y agosto, y los parques están notablemente menos concurridos.' },
  { type: 'h3', text: 'Julio y agosto: temporada alta, cruces del río Mara' },
  { type: 'p', text: 'Julio y agosto son los meses más populares para visitar el Serengueti, y con razón. Las manadas se han desplazado al norte del Serengueti y cruzan el río Mara en uno de los eventos de fauna más dramáticos del planeta. Decenas de miles de ñus se lanzan a aguas llenas de cocodrilos en cruces que pueden ocurrir varias veces al día. El paisaje de la estación seca facilita el avistamiento de fauna, los cielos están despejados y los avistamientos son de lo más fiable. Las desventajas son los precios más altos, más vehículos en los lugares más concurridos y campamentos de buena calidad completamente reservados.' },
  { type: 'h3', text: 'Septiembre y octubre: vuelta al sur' },
  { type: 'p', text: 'Las manadas regresan al sur a través del norte del Serengueti en octubre, desencadenando cruces inversos del Mara que suelen ser más tranquilos pero igualmente dramáticos. Septiembre es excelente para el avistamiento de fauna en el norte del Serengueti, y muchos viajeros experimentados lo prefieren a agosto porque las multitudes disminuyen ligeramente mientras la fauna sigue concentrada. En octubre las manadas se extienden de nuevo hacia el sur, y las lluvias cortas suelen comenzar a finales de octubre o en noviembre, refrescando el paisaje.' },
  { type: 'h3', text: 'Noviembre y diciembre: lluvias cortas y nuevos comienzos' },
  { type: 'p', text: 'Noviembre trae las lluvias cortas, que normalmente duran de tres a cuatro semanas. Los avistamientos de fauna siguen siendo buenos y los precios más bajos hacen de este período una propuesta de buen valor. En diciembre las lluvias aflojan, las llanuras del sur comienzan a verdear y las primeras ñus muy preñadas llegan antes de la temporada de partos. El Serengueti en diciembre tiene un sentido de anticipación: el ciclo se está completando y las llanuras se llenan de nuevo.' },
  { type: 'tip', title: 'El mejor mes en general', text: 'Si tuviera que elegir un solo mes, la mayoría de los guías experimentados recomendarían febrero. La temporada de partos está en su apogeo, la actividad de los depredadores es extraordinaria, los precios son razonables y el paisaje es verde y fotogénico. Junio es el mejor mes con relación calidad-precio para quienes deseen la observación de fauna de la estación seca sin las multitudes de julio y agosto.' },
  { type: 'h2', text: '¿Cuándo son más bajos los precios?' },
  { type: 'p', text: 'El período de lluvias largas —abril y mayo— ofrece los precios más bajos del año, a veces un 30-40 % por debajo de las tarifas pico. Noviembre también es más económico que el pico. Estos meses son excelentes para los viajeros con presupuesto ajustado dispuestos a aceptar que algunos campamentos cierran y que los caminos pueden ser lodosos. La recompensa en fauna por visitar en la temporada verde suele subestimarse: el paisaje es hermoso, las aves son espectaculares y la actividad de los depredadores es continua a lo largo del año.' },
  { type: 'h2', text: '¿Cuándo están más concurridos los parques?' },
  { type: 'p', text: 'Julio y agosto registran el mayor número de visitantes en el Serengueti, especialmente en la zona norte cerca del río Mara. En los puntos de cruce más populares pueden reunirse una docena o más de vehículos, muy lejos de la experiencia solitaria que muchos visitantes imaginan. Elegir un vehículo privado y un campamento situado lejos de los puntos de cruce más concurridos ayuda significativamente. El conocimiento de tu guía sobre los miradores menos visitados puede marcar la diferencia entre un espectáculo atestado y un encuentro privado.' },
  { type: 'callout', text: 'El mejor mes para visitar el Serengueti es el que se alinea con lo que más te importa, y eso requiere una conversación honesta sobre tus prioridades. Dile a tu operador si quieres la temporada de partos, los cruces del río, precios más bajos, paisajes más verdes o la máxima soledad. El Serengueti responde a todas ellas, solo que en diferentes momentos del año.' },
  { type: 'h2', text: 'Qué parte del Serengueti visitar' },
  { type: 'ul', items: [
    'Serengueti sur (zona de Ndutu): mejor de diciembre a marzo para partos y acción de depredadores',
    'Serengueti central (Seronera): fiable todo el año, especialmente bueno para leones y leopardos residentes',
    'Corredor occidental (Grumeti): mejor en junio para los cruces del río Grumeti',
    'Serengueti norte (Kogatende/Lamai): mejor de julio a octubre para los cruces del río Mara',
  ]},
  { type: 'h2', text: 'Serengueti frente a otros parques de Tanzania' },
  { type: 'p', text: 'El Serengueti es el parque más famoso de Tanzania, pero no el único extraordinario. El Parque Nacional Tarangire, al sur del Serengueti, tiene la mayor densidad de elefantes de África Oriental y una fauna aviaria excepcional. El Cráter del Ngorongoro, justo al este del Serengueti, es la caldera volcánica intacta más grande del mundo y alberga a 25.000 animales en un ecosistema autónomo que incluye al rinoceronte negro en peligro de extinción. La mayoría de los itinerarios en Tanzania combinan dos o tres parques, y el Serengueti es casi siempre el centro.' },
  { type: 'p', text: 'Llegar al Serengueti es sencillo. La mayoría de los visitantes vuelan al Aeropuerto Internacional de Kilimanjaro (JRO), cerca de Arusha, conducen o vuelan al parque y se instalan en un campamento durante tres o seis noches. Los vuelos internos entre Arusha y las pistas de aterrizaje del Serengueti duran 45 minutos y ofrecen vistas impresionantes. Los traslados por carretera a través del Área de Conservación del Ngorongoro son espectaculares pero tardan de cuatro a cinco horas. La mayoría de los itinerarios combinan ambas: entrar volando y salir en coche (o viceversa), para cubrir el paisaje dos veces.' },
],

'gorilla-trekking-rwanda': [
  { type: 'p', text: 'Quedan aproximadamente 1.000 gorilas de montaña en la Tierra. Todos viven en un único ecosistema de bosque de montaña que abarca Ruanda, Uganda y la República Democrática del Congo. Sentarse con una familia de gorilas en el neblinoso bosque de bambú de las Montañas Virunga es vivir algo que muy pocas personas experimentarán jamás, y el Parque Nacional de los Volcanes de Ruanda es donde esa experiencia es más accesible, más organizada y más extraordinaria.' },
  { type: 'h2', text: '¿Por qué Ruanda para el trekking de gorilas?' },
  { type: 'p', text: 'Ruanda y Uganda ofrecen trekking de gorilas, y Uganda es ligeramente más barata. Pero Ruanda ofrece de manera consistente una experiencia global superior. El Parque Nacional de los Volcanes está bien gestionado, las rutas de trekking son moderadas (la mayoría de las familias de gorilas se encuentran a dos o cuatro horas de camino) y la infraestructura alrededor del parque, incluyendo algunos de los mejores alojamientos de África, es excepcional. Ruanda también es más segura, más compacta y más fácil de alcanzar que el Bosque Impenetrable de Bwindi en Uganda, que requiere un largo viaje desde Entebbe o Kampala.' },
  { type: 'p', text: 'El permiso de gorila ruandés cuesta 1.500 dólares por persona, el más caro del mundo. Este precio es deliberado: los ingresos financian la protección del parque, las patrullas anticontrabando, los salarios de los guardas y los proyectos de desarrollo comunitario. En contexto, tampoco es irrazonable para una experiencia de una hora con uno de los grandes simios más amenazados de la Tierra. El dinero que gastas en un permiso de gorila va directamente al ecosistema que mantiene vivos a estos animales.' },
  { type: 'h2', text: 'Cómo obtener un permiso de gorila' },
  { type: 'p', text: 'La Junta de Desarrollo de Ruanda (RDB) emite permisos de gorila y controla la asignación de permisos. Los permisos deben reservarse con antelación a través de la RDB directamente o, de manera más fiable, a través de un operador turístico con licencia. Para los meses pico (junio, julio, agosto, diciembre y enero), los permisos se agotan con seis a doce meses de antelación. No planifiques un viaje a los gorilas de Ruanda sin confirmar primero la disponibilidad de permisos. Este es el cuello de botella crítico en todo el itinerario.' },
  { type: 'p', text: 'Solo se permiten ocho visitantes por familia de gorilas al día, y el Parque Nacional de los Volcanes tiene doce familias de gorilas habituadas disponibles para el turismo. Esto significa un máximo de 96 permisos de trekking de gorilas al día para todo el país. La escasez es intencional y esencial: minimizar el contacto humano protege a los gorilas de enfermedades y estrés. Este límite es una de las razones por las que la experiencia de gorila en Ruanda se siente tan íntima y sin prisas.' },
  { type: 'tip', title: 'Consejo para reservar el permiso', text: 'Reserva tus permisos con al menos 9-12 meses de antelación para viajar de junio a agosto. Reservar a través de un operador turístico de confianza con base en Kigali te da mejor acceso que intentar reservar directamente: los operadores suelen tener asignaciones de permisos y pueden asesorarte sobre la selección de familias.' },
  { type: 'h2', text: 'Qué familia de gorilas solicitar' },
  { type: 'p', text: 'Cada una de las doce familias de gorilas habituadas tiene un carácter diferente, un ámbito vital propio y una dificultad de trekking distinta. Algunas familias vagan a gran altitud —por encima de los 3.000 metros—, lo que requiere una exigente subida a pie con poco oxígeno. Otras se mueven a elevaciones más bajas con un acceso más fácil. El grupo Susa, una de las familias más grandes con más de 40 individuos, es famoso pero implica uno de los trekking más largos y exigentes. La familia Amahoro se recomienda a menudo para los trekkers primerizos por sus miembros tranquilos y su ámbito más accesible.' },
  { type: 'p', text: 'Tu operador turístico debería emparejarte con una familia en función de tu nivel de forma física, tu interés en el tamaño y la dinámica de la familia, y cualquier característica específica que quieras ver: machos plateados dominantes, crías, dinámicas entre familias. Esta es una pregunta que vale la pena plantear explícitamente al hacer la reserva. La familia de gorilas con la que pases tu hora definirá tu recuerdo de la experiencia.' },
  { type: 'h2', text: 'Qué ocurre el día del trekking' },
  { type: 'p', text: 'Los trekkers se reúnen en el cuartel general del parque a las 7:00 de la mañana para una sesión informativa. Los grupos son asignados a su familia de gorilas y a su guardabosques principal. El trekking comienza en el límite del parque y sigue a los guardabosques a través de bosques de bambú, vegetación densa y a veces empinadas laderas volcánicas. Los rastreadores van por delante del grupo principal, localizando a la familia de gorilas siguiendo su rastro desde donde anidaron la noche anterior.' },
  { type: 'p', text: 'Cuando los rastreadores señalan que han encontrado a la familia, el grupo avanza silenciosamente hasta una distancia segura: la separación mínima requerida es de siete metros. Entonces comienza la hora. La familia de gorilas sigue con su mañana: las crías juegan y luchan, los jóvenes se persiguen por la maleza, el macho plateado se sienta, enorme y tranquilo, en la vegetación. A veces un joven se acercará y te estudiará con ojos inteligentes que se sienten inquietantemente familiares. A veces el macho plateado se yergue sobre sus piernas —un despliegue de dominancia— y tu guardabosques mantiene su posición con calma.' },
  { type: 'p', text: 'La hora pasa muy rápido. La fotografía está permitida sin flash. El vídeo está permitido. Se pide que no comas, bebas ni uses el teléfono para llamadas. Cuando termina la hora, regresas al inicio del sendero y recibes un certificado que confirma tu trekking de gorilas. La mayoría de los trekkers describen la experiencia como una de las más profundas de sus vidas, no solo como un encuentro con la fauna salvaje, sino como un recordatorio de la delgada línea entre el ser humano y el animal.' },
  { type: 'h2', text: 'Requisitos físicos del trekking' },
  { type: 'p', text: 'El trekking de gorilas se clasifica como de moderado a arduo. La altitud del Parque Nacional de los Volcanes oscila entre 2.400 y 4.507 metros, y la mayoría de los trekking implican caminar cuesta arriba a través de un bosque denso durante una a seis horas dependiendo de dónde esté la familia ese día. No necesitas ser un atleta, pero debes poder caminar cuesta arriba durante dos o tres horas a un ritmo moderado sin detenerte. El límite de edad es de 15 años. Los mozos de cuerda están disponibles para contratar en el punto de inicio del sendero: usar un mozo está muy recomendado y proporciona ingresos a la comunidad local.' },
  { type: 'h2', text: 'Qué llevar y qué ponerse' },
  { type: 'ul', items: [
    'Camisa de manga larga y pantalón largo: el bosque tiene ortigas y insectos que pican',
    'Botas de senderismo impermeables con soporte de tobillo: esenciales para el terreno embarrado e irregular',
    'Chubasquero: las Montañas Virunga reciben lluvia todo el año, especialmente por las tardes',
    'Guantes de jardinería: útiles para agarrarse a la vegetación en las secciones empinadas',
    'Cámara con un objetivo rápido: el bosque es oscuro; f/2,8 o mayor es ideal',
    'Mochila pequeña con agua (mínimo 1,5 litros), tentempiés y crema solar',
    'Bastón de senderismo: se proporciona en el punto de inicio del sendero; merece la pena utilizarlo',
  ]},
  { type: 'h2', text: 'La mejor época para el trekking de gorilas' },
  { type: 'p', text: 'El trekking de gorilas está disponible todo el año y los gorilas no siguen un patrón migratorio. Las dos estaciones secas —de junio a septiembre y de diciembre a febrero— ofrecen las condiciones de trekking más fiables: senderos más secos, cielos más claros y caminar más fácil. Las estaciones lluviosas (de marzo a mayo y de octubre a noviembre) ven menos turistas, tarifas de alojamiento más bajas y un bosque verde exuberante. Los gorilas siguen siendo fáciles de encontrar —los rastreadores los siguen a diario—, pero los senderos son más lodosos.' },
  { type: 'h2', text: 'Combinar los gorilas de Ruanda con un safari en Tanzania' },
  { type: 'p', text: 'Ruanda y Tanzania son socios naturales en un itinerario por África Oriental. Kigali conecta directamente con el Aeropuerto Internacional de Kilimanjaro (JRO), cerca de Arusha, y muchos viajeros combinan dos o tres días de trekking de gorilas en Ruanda con un safari de cinco a ocho días en Tanzania. El contraste es notable: el íntimo encuentro en el bosque con una familia de gorilas, seguido de las vastas llanuras abiertas del Serengueti y el espectáculo de la Gran Migración.' },
  { type: 'callout', text: 'El trekking de gorilas en Ruanda es una de las pocas experiencias de fauna del mundo donde todos los que la viven —independientemente de su personalidad, intereses o experiencia viajera previa— regresan transformados. Los 1.500 dólares del permiso parecen caros hasta que estás sentado a tres metros de un gorila de montaña y te das cuenta de que estás mirando algo que puede no existir dentro de cincuenta años sin los ingresos que acabas de proporcionar.' },
],

'kilimanjaro-climbing-guide': [
  { type: 'p', text: 'El Monte Kilimanjaro se eleva a 5.895 metros sobre el nivel del mar: el punto más alto de África y la montaña de cima libre más alta del mundo. A diferencia de los picos técnicos de los Alpes o el Himalaya, el Kilimanjaro no requiere experiencia previa en escalada ni cuerdas ni equipos especializados. Lo que sí requiere es tiempo, preparación, la ruta correcta y un respeto serio por la altitud. Entre 35.000 y 50.000 escaladores intentan la cumbre cada año. Las tasas de éxito en las rutas populares oscilan entre el 45 y el 85 %, y la diferencia es casi siempre la preparación y la elección de la ruta.' },
  { type: 'h2', text: 'Comparación de las siete rutas' },
  { type: 'table', headers: ['Ruta', 'Duración', 'Tráfico', 'Tasa de éxito', 'Paisaje'], rows: [
    ['Marangu', '5-6 días', 'Alto', '~50%', 'Bueno'],
    ['Machame', '6-7 días', 'Alto', '~85%', 'Excelente'],
    ['Lemosho', '7-9 días', 'Medio', '~90%', 'Sobresaliente'],
    ['Rongai', '6-7 días', 'Bajo', '~80%', 'Bueno'],
    ['Northern Circuit', '9-10 días', 'Muy bajo', '~90%', 'Sobresaliente'],
    ['Shira', '7-8 días', 'Bajo', '~85%', 'Muy bueno'],
    ['Umbwe', '5-6 días', 'Muy bajo', '~60%', 'Muy bueno'],
  ]},
  { type: 'p', text: 'El factor más importante para elegir una ruta es el número de días de aclimatación incorporados al itinerario. Las rutas con más días —Lemosho, Northern Circuit— le dan a tu cuerpo más tiempo para adaptarse al aire más enrarecido, que es la razón principal del fracaso en la cumbre. El coste adicional de una ruta más larga casi siempre merece la pena.' },
  { type: 'h2', text: 'La ruta Machame: la más popular con razón' },
  { type: 'p', text: "La ruta Machame, a veces llamada la Ruta del Whisky, es la más popular de la montaña y una de las mejores para la aclimatación. La versión de siete días te permite seguir el principio de 'sube alto, duerme bajo' en el día cuatro, cuando subes a la Torre de Lava a 4.630 metros antes de bajar al campamento a 3.950 metros para pasar la noche. Este único día hace más por tu aclimatación que casi cualquier otra cosa que puedas hacer. Machame se aproxima desde el sur y cruza al este antes de la noche de cumbre, ofreciendo paisajes genuinamente variados y dramáticos." },
  { type: 'h2', text: 'La ruta Lemosho: la mejor en general' },
  { type: 'p', text: 'Para los escaladores con flexibilidad de tiempo y presupuesto, la ruta Lemosho en un programa de ocho o nueve días es el estándar de oro. Se aproxima desde el oeste a través de la remota Meseta Shira, uno de los paisajes más espectaculares de la montaña, antes de unirse a la ruta Machame por encima de la Torre de Lava. El amplio perfil de aclimatación, combinado con el bajo tráfico en la aproximación occidental y el extraordinario paisaje de Shira, hace que Lemosho sea la ruta que los guías más experimentados recomiendan a los escaladores serios.' },
  { type: 'p', text: 'El Lemosho de siete días es un compromiso: es excelente pero no captura el pleno beneficio del amplio perfil de ocho o nueve días. Si vas a comprometerte a escalar el Kilimanjaro, la diferencia en tiempo y coste entre siete y nueve días es pequeña en relación con la mejora en la probabilidad de éxito en la cumbre y la calidad de la experiencia.' },
  { type: 'h2', text: 'El mal de montaña: el verdadero desafío' },
  { type: 'p', text: 'El Mal Agudo de Montaña (MAM) es la principal razón por la que los escaladores no logran alcanzar la cumbre del Kilimanjaro. El MAM está causado por ascender demasiado rápido y no dar a tu cuerpo suficiente tiempo para aclimatarse a los niveles más bajos de oxígeno. Los síntomas incluyen dolor de cabeza, náuseas, fatiga, mareos y pérdida de apetito. El MAM leve es extremadamente común por encima de los 3.000 metros y es manejable. El MAM grave —que puede progresar a Edema Cerebral de Alta Altitud (ECAA) o Edema Pulmonar de Alta Altitud (EPAA)— es raro pero potencialmente mortal y requiere un descenso inmediato.' },
  { type: 'p', text: 'La regla de oro es: nunca ascender si los síntomas empeoran. Un buen guía realizará controles de salud regulares que incluyen lecturas de saturación de oxígeno. Si tu SpO2 cae por debajo del 80% y no mejora con el descanso, el descenso es el único tratamiento. La mayoría de los escaladores que no llegan a la cumbre lo hacen porque eligieron una ruta demasiado rápida, no porque no tuvieran suficiente forma física. La forma física ayuda, pero el tiempo de aclimatación es lo que te lleva a la cima.' },
  { type: 'tip', title: 'Diamox (acetazolamida)', text: 'Muchos escaladores toman Diamox (acetazolamida) para ayudar en la aclimatación. La dosis estándar es de 125-250 mg dos veces al día, comenzando 24 horas antes del ascenso. Los efectos secundarios incluyen hormigueo en las extremidades y aumento de la micción. Consulta con tu médico o clínica de viajes antes del viaje: requiere receta en la mayoría de los países.' },
  { type: 'h2', text: 'Desglose de costes del Kilimanjaro' },
  { type: 'p', text: 'Escalar el Kilimanjaro es más caro de lo que la mayoría de la gente espera. Los costes se desglosan en tasas gubernamentales del parque, salarios de guías y porteadores y tarifas del operador. Las tasas del parque para una escalada de siete días son aproximadamente 900 dólares por persona (entrada, acampada, tasas de rescate). Los salarios del equipo de guías y porteadores varían según el operador, pero un operador legítimo que pague salarios adecuados para un equipo de guía, guía asistente, cocinero y tres o cuatro porteadores costará otros 600-900 dólares por persona para una escalada de siete días. El precio total del operador legítimo para una escalada de siete días por Machame o Lemosho suele oscilar entre 2.000 y 3.500 dólares por persona.' },
  { type: 'p', text: 'Los operadores que cobran menos de 1.500 dólares por una escalada de siete días están recortando costes en algún sitio, y eso casi siempre significa pagar menos a los guías y porteadores o reducir el tamaño del equipo. Los porteadores del Kilimanjaro son de los trabajadores más maltratados de la industria turística en el nivel bajo, transportando cargas de más de 20 kg por salarios mínimos. Reservar con un operador que sea miembro del Proyecto de Asistencia a Porteadores del Kilimanjaro (KPAP) y que pague las tarifas de salario justo es tanto una obligación ética como una marca de calidad.' },
  { type: 'h2', text: 'Entrenamiento para el Kilimanjaro' },
  { type: 'p', text: 'El Kilimanjaro no requiere una forma física técnica, pero premia la resistencia cardiovascular y la fuerza en el tren inferior. La mejor preparación es el senderismo, específicamente excursiones de varios días con ganancia de altitud llevando una mochila de día. Intenta hacer al menos seis u ocho semanas de entrenamiento específico antes de tu escalada. Si vives a baja altitud, esto significa trabajar la forma física cardiovascular mediante carrera, ciclismo o escalada de escaleras, e idealmente hacer una o dos excursiones nocturnas en altitud si puedes acceder a montañas.' },
  { type: 'ul', items: [
    'Cuatro a seis meses antes: crea una base de tres o cuatro sesiones de cardio por semana (carrera, ciclismo, natación)',
    'Dos a tres meses antes: añade senderismo con una mochila de día con peso (8-12 kg) en terreno con desnivel',
    'Un mes antes: haz al menos una excursión de varios días si es posible; reduce la intensidad la semana antes del viaje',
    'El entrenamiento en altitud no es necesario y los gimnasios de gran altitud no son imprescindibles: lo que importa es la forma aeróbica constante',
  ]},
  { type: 'h2', text: 'La noche de cumbre: qué esperar' },
  { type: 'p', text: 'La noche de cumbre comienza a medianoche desde el Campamento Alto a 4.700-4.900 metros. El objetivo es llegar al Pico Uhuru antes del amanecer, alrededor de las 6:30 de la mañana. Los últimos 1.000 metros de ascenso requieren de cinco a siete horas en la oscuridad, subiendo una empinada pendiente de escoria a altitud donde cada paso requiere un esfuerzo consciente. Las temperaturas en el cráter de la cumbre oscilan entre -15 °C y -25 °C, y el viento fuerte es habitual. Tu guía lleva bebidas calientes y tentempiés.' },
  { type: 'p', text: 'La experiencia en la cumbre es difícil de describir a alguien que no ha estado allí. El campo de glaciares del Casquete de Hielo Sur resplandece con la primera luz. África se extiende 5.000 metros más abajo en todas las direcciones. El aire en el Pico Uhuru contiene aproximadamente la mitad del oxígeno que al nivel del mar. Muchos escaladores se emocionan profundamente —algunos hasta las lágrimas— por la combinación del logro físico, el surrealista paisaje y la pura grandiosidad de estar en el tejado de África.' },
  { type: 'callout', text: 'El Kilimanjaro es una montaña seria que merece una preparación seria. Los escaladores que llegan al Pico Uhuru no son necesariamente los más en forma: son los que eligieron la ruta correcta, escucharon a su guía, se mantuvieron hidratados y no se apresuraron. Date la mejor oportunidad posible eligiendo una ruta más larga y un operador cuyos guías estén certificados y tengan experiencia.' },
  { type: 'h2', text: 'Combinar el Kilimanjaro con un safari' },
  { type: 'p', text: 'Una escalada al Kilimanjaro combinada con un safari en Tanzania es una de las combinaciones de itinerario más atractivas de África Oriental. La mayoría de los escaladores añaden tres a cinco noches de safari después de la escalada: terminar en la montaña y dirigirse directamente a Tarangire, el Serengueti o el Ngorongoro. El contraste físico es extraordinario: el silencio nevado de la cumbre seguido de la cálida y bulliciosa sabana. Permite al menos un día de descanso entre el descenso y tu primera excursión para recuperarte adecuadamente antes de la siguiente aventura.' },
],

'tanzania-vs-kenya-safari': [
  { type: 'p', text: 'Tanzania y Kenia comparten el mismo extraordinario ecosistema de sabana, la misma Gran Migración y muchas de las mismas especies. Sin embargo, ofrecen experiencias de safari genuinamente distintas, lo suficientemente diferentes como para que tu elección entre ellas importe. La respuesta correcta depende de tus prioridades: multitudes, coste, calidad de los parques, actividades complementarias y el tipo de ambiente de safari que deseas.' },
  { type: 'h2', text: 'El caso de Tanzania' },
  { type: 'p', text: 'Tanzania es el país de safari más grande y biodiverso de África Oriental. Contiene aproximadamente el 30 % de la fauna salvaje restante de África y algunas de las áreas protegidas más importantes del continente. El Serengueti solo cubre 14.763 kilómetros cuadrados, casi tres veces el tamaño del Masái Mara. Los otros parques de Tanzania —Ruaha, Selous/Nyerere, Tarangire, Ngorongoro, Mahale, Gombe— ofrecen una variedad extraordinaria que Kenia no puede igualar en pura escala y diversidad.' },
  { type: 'p', text: 'La experiencia del safari en Tanzania tiende a sentirse más remota y menos concurrida que en Kenia, especialmente fuera de la temporada pico de cruces del río Mara de julio a agosto. En los parques del circuito sur —Ruaha, Nyerere— puedes pasar días enteros sin ver otro vehículo. Incluso en el Serengueti, elegir el campamento y la zona correctos elimina la mayor parte de la congestión de vehículos que frustra a los visitantes en las zonas más concurridas.' },
  { type: 'h2', text: 'El caso de Kenia' },
  { type: 'p', text: "La Reserva Masái Mara de Kenia es una de las mejores reservas de caza de África: más pequeña que el Serengueti pero con una extraordinaria densidad de fauna y una excelente red de campamentos. Kenia también ofrece una fuerte cultura de conservación privada: la meseta de Laikipia, Samburu, Amboseli y los conservancies del Mara proporcionan excursiones de safari exclusivas fuera de carretera en zonas donde las reglas de los parques nacionales de Tanzania restringen los vehículos a las pistas designadas. Los conservancies del Mara adyacentes a la reserva —Naboisho, Olare Motorogi, Mara North— son posiblemente la mejor experiencia de excursión privada de África Oriental." },
  { type: 'p', text: 'Kenia está generalmente más desarrollada en infraestructura turística, especialmente para conexiones internacionales, y puede ser ligeramente menos cara en el nivel de gama media. Nairobi conecta con una gama más amplia de rutas internacionales que Kilimanjaro o Dar es Salaam, lo que hace que Kenia sea más fácil de alcanzar desde algunas ciudades de salida. Los kenianos también se benefician de la costa swahili: Lamu y Diani Beach son excelentes destinos de playa para extensiones post-safari.' },
  { type: 'h2', text: 'Diferencias clave lado a lado' },
  { type: 'table', headers: ['Factor', 'Tanzania', 'Kenia'], rows: [
    ['Tamaño del parque', 'Mucho más grande (Serengueti 14.763 km²)', 'Más pequeño (Masái Mara 1.510 km²)'],
    ['Conducción fuera de carretera', 'No permitida en parques nacionales', 'Permitida en conservancies privados'],
    ['Nivel de masificación', 'Menor (especialmente fuera del pico)', 'Mayor alrededor del Mara'],
    ['Diversidad de parques', 'Más variada (6+ parques principales)', 'Menos opciones al mismo nivel de calidad'],
    ['Excursiones nocturnas', 'Solo en zonas privadas', 'Permitidas en conservancies del Mara'],
    ['Safaris a pie', 'Disponibles en zonas selectas', 'Disponibles en conservancies'],
    ['Extensión de playa', 'Zanzíbar (sobresaliente)', 'Lamu, Diani (buenas)'],
    ['Gran Migración', 'Ambos países; más tiempo en Tanzania', 'Cruces pico de julio a septiembre en el Mara'],
    ['Rinoceronte negro', 'Cráter del Ngorongoro', 'Conservatorio Ol Pejeta, Lewa'],
    ['Coste medio', 'Ligeramente más alto (tasas gubernamentales del parque)', 'Ligeramente más bajo en gama media'],
  ]},
  { type: 'h2', text: 'La migración: ¿qué país gana?' },
  { type: 'p', text: 'La Gran Migración pasa aproximadamente nueve o diez meses del año en Tanzania y dos o tres meses en Kenia. Si presenciar los cruces del río Mara es tu prioridad y viajas en julio, agosto o septiembre, Kenia es una opción legítima: los cruces ocurren en ambos lados de la frontera y el norte del Mara de Kenia es tan dramático como el norte del Serengueti de Tanzania durante esos meses.' },
  { type: 'p', text: 'Para cualquier otra fase de la migración —temporada de partos (enero-febrero), los cruces del Grumeti (junio), las manadas del sur del Serengueti (diciembre)— Tanzania es la única opción. Y para el ciclo global de la migración a lo largo del año, la pura escala y variedad del Serengueti tanzano te da más opciones, más espacio y más flexibilidad en tu itinerario.' },
  { type: 'h2', text: 'Primer safari: ¿cuál elegir?' },
  { type: 'p', text: 'Para un visitante primerizo que elige entre los dos países, Tanzania es la opción más sólida en general. La combinación Serengueti-Ngorongoro es el circuito de safari definitivo de África Oriental: vastas llanuras abiertas, la Gran Migración, los Cinco Grandes, paisajes volcánicos y el famoso cráter. Añadir Zanzíbar ofrece una extensión de playa que genuinamente rivaliza con las mejores del mundo. Tanzania es, en todos los parámetros, el destino de primer safari más completo.' },
  { type: 'p', text: 'Kenia destaca cuando regresas por segunda o tercera vez a África y quieres la experiencia exclusiva de los conservancies, la meseta de Laikipia o el acceso a los parques remotos del norte de Kenia como Samburu y Marsabit. Los conservancies del Mara, especialmente para las excursiones nocturnas y la conducción fuera de carretera, son también un argumento a favor de Kenia si esas experiencias específicas son una alta prioridad.' },
  { type: 'tip', title: 'La mejor respuesta: ambos', text: 'Muchos viajeros experimentados de safari combinan Tanzania y Kenia en un solo viaje, volando entre Kilimanjaro y Nairobi o tomando una conexión en avioneta programada. Un itinerario de 10-14 días puede incluir cuatro o cinco noches en el Serengueti, una noche en el Ngorongoro y cuatro noches en un conservancy del Mara. Esta combinación es insuperable.' },
  { type: 'h2', text: 'Comparación de costes' },
  { type: 'p', text: 'Tanzania es ligeramente más cara que Kenia en el nivel económico y de gama media, principalmente porque las tasas gubernamentales del parque son más altas. La tarifa del parque del Serengueti es de 82 dólares por adulto y día; las tarifas de los conservancies del Masái Mara oscilan entre 80 y 150 dólares por persona y noche, pero incluyen créditos de alojamiento en algunos campamentos. En el nivel de lujo, ambos países tienen precios similares: los campamentos de gama alta en los conservancies del Mara y el norte del Serengueti tienen tarifas equivalentes.' },
  { type: 'callout', text: 'Tanto Tanzania como Kenia son extraordinarios. La pregunta no es cuál es mejor, sino cuál es mejor para ti, en esta etapa de tu vida de safari. Si vas una sola vez y quieres la experiencia de África Oriental más icónica, más completa y más impresionante: ve a Tanzania. Si regresas y quieres exclusividad fuera de carretera, excursiones nocturnas y una perspectiva diferente del mismo ecosistema: añade Kenia.' },
],

'safari-packing-list': [
  { type: 'p', text: 'Lo que llevas a un safari importa más de lo que la mayoría de la gente piensa. Demasiado equipaje y no cabes cómodamente en un pequeño avión hacia tu campamento. Ropa incorrecta y tendrás frío en las excursiones antes del amanecer o sudarás con camisas de algodón con el calor. Sin crema solar y te quemarás a través de la escotilla abierta del techo en quince minutos. Nuestros guías han visto todos los errores de equipaje: aquí está la lista definitiva de qué llevar y qué dejar en casa.' },
  { type: 'h2', text: 'Normas de equipaje: el punto de partida crítico' },
  { type: 'p', text: 'Los traslados en avioneta entre pistas de aterrizaje en Tanzania y Kenia tienen un límite de equipaje estricto de 15 kg en total, incluido el equipaje de mano, y la bolsa debe ser de lona blanda (sin maletas rígidas). Esta no es una sugerencia; es una norma estricta que se aplica en el registro y en el avión. Si vas a hacer cualquier combinación de campamentos conectados por vuelos de bush, lleva una bolsa de lona blanda que cumpla estos límites.' },
  { type: 'p', text: 'Si solo haces un safari por carretera, conduciendo entre todos los campamentos, tienes más flexibilidad en el tamaño de la bolsa, pero una bolsa de lona blanda sigue siendo preferible para caber en el almacenamiento del techo del vehículo. Las maletas rígidas son poco prácticas en safari y molestas de manejar. Empaca ligero, empaca en colores neutros y deja el equipaje con ruedas en casa o en tu hotel de Arusha.' },
  { type: 'h2', text: 'Ropa: qué empacar' },
  { type: 'ul', items: [
    'Tres o cuatro camisas de manga larga en colores neutros (caqui, oliva, tostado, beige, gris claro)',
    'Dos o tres pantalones largos o pantalones de safari con perneras desmontables',
    'Un par de pantalones cortos para el campamento y el uso casual',
    'Un forro polar ligero o una chaqueta de plumón: las excursiones matutinas por debajo de 2.000 m pueden ser frías',
    'Un forro polar más grueso o una chaqueta de plumón ligera para destinos de gran altitud (Ngorongoro, base del Kilimanjaro)',
    'Chubasquero impermeable: esencial incluso en la estación seca para las lluvias vespertinas y el viento en altitud',
    'Cuatro o cinco pares de ropa interior transpirable: lana merino o sintética',
    'Dos o tres pares de calcetines ligeros de lana merino para las excursiones; un par separado para el senderismo',
    'Zapatos cómodos para caminar o zapatillas de trail para el campamento y los paseos cortos',
    'Botas de senderismo impermeables hasta el tobillo si vas a hacer trekking de gorilas o paseos por el bush',
    'Sandalias o chanclas para el campamento y el uso en el alojamiento',
    'Sombrero de ala ancha para las excursiones: el sol cenital es intenso a través de la escotilla abierta del techo',
    'Gorro de lana para las excursiones con frío matutino: más útil de lo que la mayoría espera',
    'Buff o pañuelo ligero: útil para el polvo y el frío en las excursiones en vehículo abierto',
  ]},
  { type: 'tip', title: 'Evita el blanco y los colores brillantes', text: 'La ropa blanca atrae a los insectos (especialmente a las moscas tsetsé en algunas zonas), se mancha de polvo al instante y perturba a la fauna que de otro modo permanecería tranquila cerca de tu vehículo. Cíñete estrictamente a los tonos tierra. Deja en casa la ropa de marca safari: no es necesaria y a menudo parece exactamente lo que es: equipamiento de turista.' },
  { type: 'h2', text: 'Equipo fotográfico' },
  { type: 'p', text: 'La fotografía es una de las principales razones por las que la gente va de safari. Tu configuración de cámara determina cuánto de la experiencia capturas frente a cuánto simplemente observas. Para la mayoría de las personas, una cámara sin espejo con un zoom teleobjetivo de 100-400 mm es el sistema todo en uno ideal. El Canon RF 100-500 mm, el Nikon Z 100-400 mm o el Sony 100-400 mm GM son excelentes opciones. Para los fotógrafos con presupuesto ajustado, una cámara bridge superzoom en el rango de 400-600 mm ofrece buenos resultados sin el coste de un teleobjetivo dedicado.' },
  { type: 'ul', items: [
    'Cuerpo de cámara: sin espejo o DSLR preferible; las modernas cámaras de teléfono inteligente son sorprendentemente capaces como respaldo',
    'Objetivo: mínimo 300 mm; 400-500 mm es ideal; 600 mm es útil para animales muy tímidos o lejanos',
    'Baterías adicionales: carga cada noche; las mañanas frías agotan las baterías más rápido',
    'Tarjetas de memoria: lleva al menos 128 GB en total; los fallos de las tarjetas SD ocurren',
    'Saco de arena: descansa en el borde de la ventanilla del vehículo para una plataforma de disparo estable: mejor que cualquier monópode en un vehículo en movimiento',
    'Paño para el objetivo: el polvo es omnipresente; limpia el elemento frontal diariamente',
    'Bolsa estanca o cubierta para lluvia de cámara: para chubascos inesperados en vehículos abiertos',
  ]},
  { type: 'h2', text: 'Suministros médicos y de salud' },
  { type: 'ul', items: [
    'Profilaxis antimalárica (doxiciclina, Malarone o mefloquina): consulta con tu médico o clínica de viajes; comienza antes del viaje',
    'Repelente de insectos con DEET (30-50 % de DEET): esencial al amanecer y al anochecer',
    'Crema solar SPF 50+: el sol ecuatorial a través de una escotilla abierta en el techo es severo; aplica cada dos horas',
    'Gafas de sol con protección UV: las lentes polarizadas reducen significativamente el deslumbramiento',
    'Crema antihistamínica para las picaduras de insectos',
    'Immodium y sales de rehidratación oral para la diarrea del viajero',
    'Botiquín de primeros auxilios básico: tiritas, toallitas antisépticas, tiritas para ampollas, ibuprofeno, paracetamol',
    'Medicamentos con receta personal con suficiente suministro más extra para retrasos',
    'Medicación para el mal de montaña (Diamox) si asciendes por encima de los 3.000 m: requiere receta',
  ]},
  { type: 'h2', text: 'Esenciales del safari' },
  { type: 'ul', items: [
    'Prismáticos (8×42 es la especificación ideal para safari): esenciales para avistar animales lejanos',
    'Linterna frontal: útil para navegar por el campamento por la noche; puede haber fauna alrededor después del oscurecer',
    'Batería externa: carga dispositivos entre excursiones si tu habitación no tiene electricidad las 24 horas',
    'Adaptador de viaje universal: Tanzania usa enchufes tipo G (UK); Kenia también usa tipo G',
    'Bolsa estanca o bolsas con cierre hermético para la electrónica en condiciones de polvo o lluvia',
    'Guía de campo: la Guía de Campo Kingdon de Mamíferos Africanos o las Aves de África Oriental enriquecen cada excursión',
  ]},
  { type: 'h2', text: 'Qué dejar en casa' },
  { type: 'ul', items: [
    'Ropa de camuflaje: ilegal en algunos países de África Oriental, inapropiada en todas partes en safari',
    'Perfume y colonia fuerte: atrae a los insectos y perturba a la fauna',
    'Maletas rígidas: poco prácticas en los vuelos de bush y en el almacenamiento del vehículo',
    'Joyas en exceso: riesgo de robo e inapropiadas para el entorno',
    'Demasiado calzado: usarás dos pares como máximo; un par de botas y un par de sandalias',
    'Secador de pelo: la mayoría de los campamentos de calidad proporcionan uno; es peso muerto en tu bolsa',
  ]},
  { type: 'callout', text: 'La bolsa de safari mejor empacada es la que puedes levantar con una sola mano. Cada kilo adicional es uno que cargas por los aeropuertos, en los compartimentos superiores de los aviones y hacia los campamentos con tiendas donde los mozos no siempre están disponibles. Empaca la lista anterior, resiste añadir extras y pasarás tu viaje enfocado en la fauna, no en gestionar tu equipaje.' },
],

'big-five-africa-tanzania': [
  { type: 'p', text: "El término 'Cinco Grandes' se originó con los cazadores coloniales que designaron los cinco animales más difíciles —y peligrosos— de cazar a pie: el león, el leopardo, el elefante africano, el búfalo africano y el rinoceronte. Hoy los Cinco Grandes son el centro de toda lista de deseos de safari en África Oriental, no porque sean los cinco animales más grandes, sino porque son cinco de los más impresionantes, más codiciados y más emocionantes de encontrar en estado salvaje. Tanzania es uno de los mejores lugares de la Tierra para ver los cinco." },
  { type: 'h2', text: "León: el orgullo de Tanzania" },
  { type: 'p', text: 'Tanzania alberga la mayor población de leones de cualquier país de África: aproximadamente entre 8.000 y 10.000 individuos, que representan alrededor del 40 % de los leones salvajes restantes en el continente. El ecosistema Serengueti-Ngorongoro es el hábitat de leones más importante del mundo. Aquí los leones viven en grandes manadas y están tan expuestos a los vehículos que puedes observar el comportamiento natural a corta distancia: cacerías matutinas al amanecer, reuniones familiares a mediodía bajo las acacias, las dramáticas interacciones entre machos rivales.' },
  { type: 'p', text: 'El corredor central del Serengueti alrededor de Seronera es famoso por los avistamientos de leones: las manadas residentes de esta zona están tan habituadas a los vehículos que caminan a metros de tu 4×4 sin preocupación. Pero la densidad de leones es alta en todo el Serengueti, en el Cráter del Ngorongoro, en Tarangire y en Ruaha, que alberga una de las poblaciones de leones más fuertes de Tanzania fuera del circuito norte.' },
  { type: 'h2', text: 'Leopardo: el esquivo' },
  { type: 'p', text: 'Los leopardos están presentes en toda Tanzania, pero son solitarios, nocturnos y maestros del camuflaje. En el Serengueti, los mejores avistamientos de leopardos se producen en los afloramientos rocosos y el bosque ribereño del Valle de Seronera, donde se ha estudiado a leopardos individuales durante décadas y están relativamente habituados a los vehículos. Los leopardos descansan en los árboles durante el día: busca la característica cola que cuelga de una rama horizontal. El conocimiento que tiene tu guía de los territorios de los animales individuales marca la diferencia entre encontrar un leopardo y no encontrarlo.' },
  { type: 'p', text: 'El Parque Nacional Tarangire está subestimado para los leopardos. La combinación de bosque ribereño, colinas rocosas y vegetación densa a lo largo del río Tarangire crea un hábitat ideal para el leopardo, y los avistamientos son fiables si pasas suficiente tiempo en las zonas correctas. El Lago Manyara también tiene una pequeña población de leones trepadores de árboles —un famoso fenómeno local donde los leones descansan en las ramas— y los leopardos están presentes en las secciones de bosque.' },
  { type: 'h2', text: "Elefante africano: los gigantes de Tanzania" },
  { type: 'p', text: 'Tanzania alberga una de las mayores poblaciones de elefantes de África, aproximadamente 60.000 individuos, y los elefantes de Tarangire son famosos por su tamaño y sus colmillos. El Parque Nacional Tarangire tiene la mayor densidad de elefantes de cualquier parque de África Oriental, y durante la estación seca (junio-octubre) cientos de elefantes se congregan a lo largo del río Tarangire en concentraciones que hay que ver para creerlas.' },
  { type: 'p', text: 'Los elefantes de Amboseli en Kenia y Ruaha en Tanzania también son famosos por producir grandes toros con enormes colmillos. En el Serengueti, los avistamientos de elefantes son fiables en las zonas fluviales y en la sección norte cerca del río Mara. El Cráter del Ngorongoro tiene una población residente de elefantes que incluye a algunos de los toros más antiguos e impresionantes de África. El Parque Nacional Nyerere (anteriormente Selous) en el sur de Tanzania tiene la mayor población de elefantes de cualquier área protegida de África.' },
  { type: 'h2', text: 'Búfalo africano: subestimado y magnífico' },
  { type: 'p', text: "El búfalo africano es posiblemente el más subestimado de los Cinco Grandes. A menudo ignorado en favor del más glamuroso león y leopardo, los búfalos son en realidad fascinantes: son masivamente sociales (las manadas de miles son comunes en el Serengueti), físicamente formidables (un toro adulto pesa hasta 900 kg) y conductualmente complejos. Los viejos toros que abandonan la manada, conocidos como 'dagga boys', son notoriamente irascibles y se consideran los más peligrosos de todos los Cinco Grandes cuando se aproxima uno a pie." },
  { type: 'p', text: 'Los búfalos están presentes en grandes cantidades en toda Tanzania. El Serengueti tiene enormes manadas, a veces de miles de animales, especialmente en las secciones norte y occidental. El Cráter del Ngorongoro tiene una población residente significativa. Tarangire, el Lago Manyara y Ruaha ofrecen excelentes avistamientos de búfalos. A diferencia de algunos de los Cinco Grandes más esquivos, los avistamientos de búfalos están prácticamente garantizados en cualquier safari en Tanzania.' },
  { type: 'h2', text: 'Rinoceronte: la prioridad de conservación' },
  { type: 'p', text: 'Los rinocerontes son los más difíciles de ver de los Cinco Grandes en Tanzania y en África en general. El rinoceronte negro fue devastado por la caza furtiva en los años setenta y ochenta, y aunque las poblaciones se están recuperando, siguen estando en peligro crítico con menos de 6.000 individuos supervivientes en estado salvaje en todo el continente.' },
  { type: 'p', text: 'El Cráter del Ngorongoro es el mejor lugar de Tanzania para ver el rinoceronte negro, con aproximadamente 25 individuos viviendo en el fondo del cráter. Este número puede parecer pequeño —y lo es—, pero la geografía cerrada del cráter y la excelente protección de los guardabosques lo convierten en uno de los lugares más fiables de África para ver el rinoceronte negro en estado salvaje. Los avistamientos no están garantizados, pero un día completo en el cráter te da una buena oportunidad. El Serengueti también tiene una pequeña población de rinocerontes en la zona de Moru Kopjes, aunque los avistamientos son menos predecibles.' },
  { type: 'tip', title: 'Consejo para ver rinocerontes', text: 'Para ver rinocerontes en el Ngorongoro, llega al fondo del cráter a la hora de apertura y dirígete directamente a la zona de las fuentes de Ngoitokitok en el fondo oriental del cráter: este es el territorio más fiable de los rinocerontes. Tu guía debería conocer las zonas de movimiento habitual de los animales individuales.' },
  { type: 'h2', text: 'Los mejores parques para los cinco' },
  { type: 'table', headers: ['Animal', 'Mejor parque', 'Segundo mejor', 'Notas'], rows: [
    ['León', 'Serengueti', 'Cráter del Ngorongoro', 'Muy fiable en el Valle de Seronera'],
    ['Leopardo', 'Serengueti (Seronera)', 'Tarangire', 'Nocturno: mejor al amanecer y al anochecer'],
    ['Elefante', 'Tarangire', 'Serengueti', 'La concentración en la estación seca es extraordinaria'],
    ['Búfalo', 'Serengueti', 'Cráter del Ngorongoro', 'Enormes manadas en el norte del Serengueti'],
    ['Rinoceronte', 'Cráter del Ngorongoro', 'Serengueti (Moru Kopjes)', 'Solo ~25 en el fondo del cráter; se requiere paciencia'],
  ]},
  { type: 'h2', text: 'Más allá de los Cinco Grandes' },
  { type: 'p', text: 'La fauna de Tanzania va mucho más allá de los Cinco Grandes. El país tiene la mayor población de guepardos de África Oriental, perros salvajes (uno de los carnívoros más amenazados de África, que se ven mejor en Ruaha y Nyerere), enormes cocodrilos e hipopótamos en cada río y una avifauna de más de 1.100 especies. El concepto de los Cinco Grandes es útil para planificar, pero corre el riesgo de estrechar tu visión: algunos de los encuentros con fauna más emocionantes en Tanzania implican animales que no están en la lista de caza original.' },
  { type: 'callout', text: 'Ver los cinco Grandes en un solo safari en Tanzania es más factible de lo que la gente piensa. Un safari de siete días por el Circuito Norte que combine Tarangire, el Serengueti y el Cráter del Ngorongoro cubre los hábitats principales de las cinco especies. Con un guía experto y buena suerte con el rinoceronte, el comodín, un safari de los Cinco Grandes en Tanzania es absolutamente alcanzable.' },
],

'zanzibar-travel-guide': [
  { type: 'p', text: 'Zanzíbar es uno de esos lugares que recompensa simplemente con llegar. El aire huele a clavo, cardamomo y al Océano Índico. Los antiguos edificios de piedra de coral de Stone Town y las talladas puertas de madera bordean angostos callejones que han acogido a comerciantes, sultanes y exploradores durante seis siglos. Y luego están las playas: arena blanca de coral, agua turquesa cálida y una sensación de languidez del Océano Índico que hace que el final de un safari en Tanzania parezca el comienzo de una segunda aventura completamente diferente.' },
  { type: 'h2', text: 'Stone Town: el corazón histórico' },
  { type: 'p', text: 'Stone Town es Patrimonio de la Humanidad de la UNESCO y uno de los ejemplos más intactos de la cultura comercial costera swahili de África Oriental. Su arquitectura es extraordinaria: casas de comerciantes árabes con intrincadas puertas de madera tallada, baños persas, barrios de mercaderes indios, una capilla portuguesa y la Casa de las Maravillas, el primer edificio de África Oriental que tuvo electricidad y ascensor. Caminar por el casco antiguo sin mapa y perderse por los callejones es uno de los grandes placeres de bajo perfil tecnológico de viajar por África Oriental.' },
  { type: 'p', text: 'El mercado nocturno de los Jardines Forodhani, frente al mar, sirve la famosa comida callejera de Zanzíbar: marisco fresco a la parrilla sobre brasas, pizza zanzibari (una masa doblada rellena de carne, queso y huevo), zumo de caña de azúcar y dulces a base de coco. Comer aquí es la mejor introducción a la cocina zanzibari. Durante el día, el mercado de Darajani vende las especias que hicieron famosa a Zanzíbar: clavo, nuez moscada, canela, pimienta negra, vainilla y cardamomo.' },
  { type: 'h2', text: 'Las mejores playas' },
  { type: 'p', text: 'Las playas de Zanzíbar varían dramáticamente en carácter, y elegir la adecuada para tu visita depende de lo que busques. Las playas de la costa este —Paje, Bwejuu, Kiwengwa— dan al Océano Índico y son conocidas por su arena blanca fina y sus excelentes condiciones para el kitesurf (los vientos de la monzón sureste soplan de forma constante de junio a octubre). La costa norte —Nungwi y Kendwa— tiene aguas más calmadas y profundas en las que se puede nadar con cualquier marea, lo que la convierte en el destino más popular para el descanso en la playa en general.' },
  { type: 'table', headers: ['Zona de playa', 'Ideal para', 'Condiciones del agua', 'Ambiente'], rows: [
    ['Nungwi', 'Vacaciones en playa en general, snorkel', 'Tranquila, nadable con cualquier marea', 'La más concurrida; más hoteles y restaurantes'],
    ['Kendwa', 'Natación, fiestas al atardecer', 'Tranquila, nadable con cualquier marea', 'Animada; famosas fiestas de luna llena'],
    ['Paje', 'Kitesurf, viajeros económicos', 'Poco profunda en marea baja', 'Joven y social; gran escena de kite'],
    ['Bwejuu', 'Relajación tranquila', 'Poco profunda en marea baja', 'Tranquila; menos desarrollada'],
    ['Matemwe', 'Snorkel en el arrecife, reclusión', 'Poco profunda en marea baja', 'Tranquila; buena para parejas'],
    ['Jambiani', 'Cultura de algas marinas, económica', 'Poco profunda en marea baja', 'Experiencia de pueblo auténtica'],
  ]},
  { type: 'h2', text: 'Vida marina y actividades acuáticas' },
  { type: 'p', text: 'Zanzíbar se encuentra dentro del sistema de arrecifes de coral del Océano Índico occidental, uno de los entornos marinos más biodiversos del mundo. El arrecife alrededor del Atolón Mnemba, a un corto viaje en barca desde la costa noreste cerca de Matemwe, es uno de los mejores sitios de snorkel y buceo del Océano Índico. Delfines de hocico largo, tortugas verdes, tortugas de carey, mantarrayas y tiburones ballena están presentes en las aguas zanzibaris en distintas épocas del año.' },
  { type: 'p', text: 'Los encuentros con tiburones ballena se organizan desde Nungwi y otras localidades de la costa norte de octubre a febrero, cuando los animales se congregan en las cálidas aguas alrededor de la isla. Nadar con tiburones ballena —el pez más grande del mundo, perfectamente inofensivos filtradores— es una experiencia genuinamente extraordinaria. Los operadores responsables siguen directrices de encuentro responsable: no tocar, mantener la distancia, limitar el tamaño del grupo. Reserva únicamente con operadores certificados.' },
  { type: 'h2', text: 'Tours de especias' },
  { type: 'p', text: 'Zanzíbar fue el mayor productor mundial de clavo durante gran parte de los siglos XIX y XX, y el cultivo de especias sigue siendo fundamental para la identidad de la isla. Una excursión de medio día a una granja de especias desde Stone Town te lleva a granjas en activo donde los guías te conducen por jardines de clavo, nuez moscada, canela, vainilla, pimienta y árboles de ylang-ylang, probando, oliendo y comprendiendo la especia que hizo famosa a esta isla. Es una experiencia relajada y sensorial que te conecta con la historia de la isla de una manera que ningún museo logra del todo.' },
  { type: 'h2', text: 'Combinar Zanzíbar con un safari en Tanzania' },
  { type: 'p', text: 'La mayoría de los operadores de safari en Tanzania incluyen Zanzíbar como extensión natural: vuelo desde el Serengueti o el Kilimanjaro al Aeropuerto de Zanzíbar (ZNZ) y pasa de tres a cinco noches en la isla antes de volar a casa. Esta combinación —las salvajes y polvorientas llanuras abiertas seguidas del suave turquesa del Océano Índico— es uno de los mejores contrastes de vacaciones disponibles en cualquier parte del mundo.' },
  { type: 'p', text: 'La logística es sencilla: los vuelos programados desde Arusha (JRO) a Zanzíbar duran aproximadamente 45 minutos. De Dar es Salaam a Zanzíbar hay un vuelo de 20 minutos o un ferry rápido de 70 minutos. La mayoría de los operadores pueden organizar traslados fluidos entre tu safari y tu alojamiento en Zanzíbar sin ningún estrés adicional de tu parte.' },
  { type: 'tip', title: '¿Cuánto tiempo en Zanzíbar?', text: 'Tres noches es el mínimo para ver Stone Town y una zona de playa. Cinco noches es lo ideal: dos en Stone Town explorando el casco antiguo y el paseo marítimo, tres en la playa de Nungwi o Paje. Siete noches te permiten experimentar varias zonas de playa y añadir buceo, snorkel con tiburones ballena o el santuario de tortugas de Isla Prisión.' },
  { type: 'h2', text: 'Cuándo ir' },
  { type: 'p', text: 'Zanzíbar tiene dos estaciones lluviosas que se corresponden aproximadamente con las de Tanzania: las lluvias largas de marzo a mayo y las lluvias cortas en noviembre. La estación seca de junio a octubre es el período más popular, con temperaturas cálidas, sol constante y excelentes condiciones de buceo. Enero y febrero también son excelentes: cálidos, principalmente secos y el período en que los tiburones ballena están más presentes de forma fiable. De marzo a mayo los precios son más bajos, pero las lluvias son más intensas.' },
  { type: 'callout', text: 'Zanzíbar no existe para ser explorada con prisas. La isla tiene un ritmo —lento, especiado, refrescado por el océano— que está completamente en desacuerdo con la intensidad del safari. Date suficiente tiempo para dejar que ese ritmo te encuentre. Las playas son excepcionales, pero son solo una parte de lo que hace extraordinaria a Zanzíbar. Los callejones de Stone Town al atardecer, el llamado a la oración resonando en las paredes de piedra coral, el olor a clavo en el mercado matutino: estas son las cosas que recordarás años después.' },
],

'safari-honeymoon-tanzania': [
  { type: 'p', text: 'Un safari de luna de miel en Tanzania no es simplemente unas vacaciones románticas: es una inmersión en un mundo tan diferente de la vida ordinaria que sacude hasta los cimientos todos los supuestos sobre lo que importa. Observas cómo una leona caza al amanecer desde un vehículo a treinta metros. Te sientas en una piscina infinita en la azotea con el Serengueti extendiéndose dorado hasta el horizonte. Cenas bajo un cielo tan repleto de estrellas que parece artificial. Si quieres una luna de miel de la que ninguno de los dos dejará de hablar jamás, Tanzania te la da.' },
  { type: 'h2', text: '¿Por qué Tanzania para una luna de miel?' },
  { type: 'p', text: 'Tanzania funciona como destino de luna de miel porque combina dos experiencias que no tienen rival en ningún otro lugar del mundo: la fauna del Serengueti y el Ngorongoro, y las playas de Zanzíbar. El contraste —el salvaje y polvoriento bush seguido de la suave arena del Océano Índico— es el arco perfecto de una luna de miel. Llegas al campamento todavía electrizado por la excursión; abandonas Zanzíbar descansado, bronceado y ya planeando tu regreso.' },
  { type: 'p', text: 'La experiencia del campamento de safari de lujo es también inherentemente romántica. Pequeños campamentos de ocho a dieciséis tiendas, duchas exteriores privadas bajo las estrellas, hogueras con cócteles al atardecer y excursiones realizadas íntegramente en un vehículo privado con tu guía personal crean un nivel de privacidad e intimidad que un hotel de resort simplemente no puede replicar. El bush por la noche —los llamados de las hienas, el parpadeo de las luciérnagas, el silencio absoluto entre los sonidos— es una experiencia que pertenece a una luna de miel.' },
  { type: 'h2', text: 'El itinerario ideal de luna de miel' },
  { type: 'p', text: 'De diez a catorce días es la duración ideal de una luna de miel en Tanzania. La combinación clásica es de cuatro a cinco noches de safari en el circuito norte —el Serengueti y el Ngorongoro como base, con extensión opcional a Tarangire— seguidas de cinco a siete noches en Zanzíbar. Vuela entre el safari y la playa (45 minutos desde el Kilimanjaro al Aeropuerto de Zanzíbar) y la transición es perfecta.' },
  { type: 'table', headers: ['Días', 'Ubicación', 'Experiencia'], rows: [
    ['Días 1-2', 'Tarangire o Lago Manyara', 'Llegar, aclimatarse, primeras excursiones; manadas de elefantes'],
    ['Días 3-5', 'Serengueti central/norte', 'Excursiones de día completo; Gran Migración (estacional)'],
    ['Día 6', 'Cráter del Ngorongoro', 'Día completo en el fondo del cráter; Cinco Grandes'],
    ['Día 7', 'Traslado a Zanzíbar', 'Volar Kilimanjaro-Zanzíbar; llegada tarde a Stone Town'],
    ['Días 8-9', 'Stone Town', 'Paseo por el casco antiguo, mercado de mariscos, tour de especias, crucero en dhow al atardecer'],
    ['Días 10-13', 'Playa de Nungwi o Matemwe', 'Playa, snorkel, buceo, relajación'],
    ['Día 14', 'Salida', 'Conexión Zanzíbar-casa'],
  ]},
  { type: 'h2', text: 'Elegir el campamento adecuado para la luna de miel' },
  { type: 'p', text: 'Para una luna de miel, la elección del alojamiento importa más que en ningún otro momento. Quieres un campamento con romance genuino, no solo comodidad. Busca campamentos con baños exteriores privados, terrazas privadas con vistas al bush, opciones de cena a la luz de las velas y la posibilidad de organizar experiencias privadas: cenas en el bush, excursiones privadas al amanecer antes de que salgan otros vehículos, aperitivos al atardecer en un mirador reservado solo para tu vehículo.' },
  { type: 'p', text: 'El norte del Serengueti tiene algunos de los campamentos más románticos de África, especialmente los situados junto al propio río Mara o en el Triángulo Lamai con vistas a los puntos de cruce. Los campamentos durante la temporada de migración aquí ofrecen la extraordinaria combinación del drama de los cruces del río durante el día y el completo silencio de la naturaleza salvaje por la noche. Las mejores propiedades para luna de miel de Zanzíbar se concentran alrededor de Matemwe, Nungwi y las islas privadas de la costa noreste.' },
  { type: 'tip', title: 'Comunica que es tu luna de miel', text: 'Dile a tu operador que es una luna de miel cuando reserves. La mayoría de los campamentos de calidad ofrecen detalles de luna de miel gratuitos: flores y champán a la llegada, una cena en el bush para dos, un servicio de colaciones especial. Estos detalles no le cuestan mucho al campamento, pero marcan una diferencia significativa en tu primera noche en el bush.' },
  { type: 'h2', text: 'Zanzíbar para los recién casados' },
  { type: 'p', text: 'La extensión de playa en Zanzíbar no es un añadido de último momento: es el contrapunto que hace que todo el itinerario cante. Después de la intensidad y la adrenalina del safari, el Océano Índico no te pide nada más que estar presente. Hacer snorkel en el arrecife del Atolón Mnemba, un crucero al atardecer en dhow con champán frío, un tratamiento de spa para parejas en un pabellón al aire libre con vistas al océano: estos son los momentos que equilibran el drama salvaje del Serengueti.' },
  { type: 'p', text: 'Las islas privadas al norte de Zanzíbar —Mnemba, Chumbe y otras— ofrecen la experiencia más recogida. Estas pequeñas propiedades en islas privadas acogen a un puñado de huéspedes a la vez, incluyen todas las comidas y actividades, y proporcionan un nivel de soledad imposible en la isla principal. Si tu presupuesto lo permite, una estancia de dos noches en uno de estos complejos insulares es el final romántico definitivo de una luna de miel en Tanzania.' },
  { type: 'h2', text: 'Expectativas de presupuesto' },
  { type: 'p', text: 'Una luna de miel de calidad en Tanzania —campamentos de lujo en el Serengueti y el Ngorongoro, alojamiento en playa cómodo pero no ultra lujo en Zanzíbar, vehículos privados en todo momento— cuesta normalmente entre 8.000 y 15.000 dólares por pareja en destino (excluyendo los vuelos internacionales). Las opciones ultra lujo con campamentos móviles, estancias en islas privadas y cenas en el bush en avioneta pueden alcanzar entre 20.000 y 30.000 dólares por pareja. Los recién casados con presupuesto ajustado pueden tener una experiencia preciosa en gama media alta por entre 5.000 y 8.000 dólares por pareja.' },
  { type: 'callout', text: 'La fórmula de la luna de miel en Tanzania funciona porque ofrece dos estados emocionales distintos: salvaje y vivo en el bush, luego en paz y a gusto en la playa. La transición entre esos dos estados —el momento en que aterrizas en Zanzíbar, hueles el aire del océano y sientes que el ritmo cambia completamente— es en sí mismo uno de los momentos más memorables de todo el viaje.' },
],

'family-safari-africa': [
  { type: 'p', text: 'Un safari en familia en África es una de las experiencias más transformadoras que puedes dar a los niños, y una de las más gratificantes que puedes compartir con ellos como padre. Ver la cara de tu hijo cuando un elefante salvaje se acerca a diez metros del vehículo, o cuando un guepardo cruza la carretera frente a ti, es algo que permanece en la historia de una familia durante generaciones. La pregunta no es si llevar a los niños de safari, sino cómo planificarlo para que la experiencia sea segura, adecuada para su edad e inolvidable para todos.' },
  { type: 'h2', text: 'Requisitos de edad mínima' },
  { type: 'p', text: 'La mayoría de los operadores de safari en Tanzania y los parques nacionales permiten niños de seis años en adelante en las excursiones estándar. Algunos campamentos exclusivos fijan el mínimo en doce años para ciertas actividades, especialmente los safaris a pie y las excursiones nocturnas. Los safaris de acampada económicos con vehículos compartidos suelen fijar una edad mínima más alta —entre ocho y diez años— porque los largos viajes y los madrugones son más difíciles de gestionar para los niños pequeños.' },
  { type: 'p', text: 'Para el trekking de gorilas en Ruanda, la edad mínima es de quince años, fijada por la Junta de Desarrollo de Ruanda y aplicada estrictamente. Los niños menores de quince años no pueden participar en el trekking de gorilas independientemente del operador o el consentimiento parental. Si el trekking de gorilas está en la lista de deseos de tu familia, planifica para cuando tu hijo menor tenga la edad suficiente.' },
  { type: 'h2', text: 'Los mejores parques para familias' },
  { type: 'p', text: 'No todos los parques de Tanzania son igualmente aptos para familias. La mejor elección depende de la edad e intereses de tus hijos. El Parque Nacional Tarangire es un destino familiar excepcional: la población de elefantes es extraordinaria (cientos de elefantes alrededor de las fuentes de agua en la estación seca), los paisajes son variados y dramáticos, y las distancias más cortas desde Arusha reducen el tiempo de viaje. El Cráter del Ngorongoro también es excelente: la geografía cerrada significa alta densidad de fauna y avistamientos fiables que mantienen a los niños entretenidos.' },
  { type: 'p', text: 'Para familias con niños mayores y adolescentes, el Serengueti ofrece la experiencia más dramática, especialmente durante la temporada de partos (enero-febrero) cuando la pura abundancia de interacciones depredador-presa mantiene a los adolescentes incluso adictos al teléfono completamente cautivados. Los niños más pequeños (de seis a diez años) suelen responder mejor al drama visual del Ngorongoro y Tarangire que al paisaje más amplio del Serengueti, donde las distancias entre avistamientos pueden ser más largas.' },
  { type: 'h2', text: 'Vehículos privados frente a compartidos' },
  { type: 'p', text: 'Para las familias, un vehículo privado no es un lujo, es una necesidad práctica. Un vehículo privado te permite marcar el ritmo, parar cuando los niños necesitan estirarse o ir al baño, pasar más tiempo en los avistamientos que les fascinan y marcharse cuando los niños pequeños alcanzan su límite. Los vehículos compartidos en los safaris en grupo siguen un horario que sirve al adulto medio, no a un niño de siete años que lleva tres horas sentado quieto.' },
  { type: 'p', text: 'Los vehículos privados también le dan a tu guía la libertad de ofrecer una experiencia genuinamente educativa: parar para explicar huellas, plantas, reclamos de aves y el ecosistema de una manera adaptada a los intereses de tus hijos. Los mejores guías de safari familiar son hábiles para involucrar a los niños: haciendo preguntas, implicándolos en la observación, enseñándoles a identificar animales. Esta dimensión educativa transforma un viaje de avistamiento en una experiencia que da forma a cómo los niños entienden el mundo natural.' },
  { type: 'h2', text: 'Consejos prácticos para el safari con niños' },
  { type: 'ul', items: [
    'Reserva campamentos con habitaciones familiares o tiendas contiguas: muchos campamentos de lujo tienen unidades familiares diseñadas específicamente',
    'Elige campamentos con piscina: esenciales para los descansos de tarde entre excursiones',
    'Lleva una guía de fauna para la edad adecuada de tu hijo: DK Eyewitness Safari es excelente para niños de 8 a 14 años',
    'Lleva prismáticos para cada niño: tener los suyos transforma la observación pasiva en participación activa',
    'Incorpora tiempo de descanso: intentar hacer cuatro excursiones al día con niños menores de diez años lleva al agotamiento y las lágrimas',
    'Las excursiones de primera hora de la mañana son las más productivas, pero deja que los niños duerman una mañana por viaje',
    'Lleva un cuaderno pequeño para que los niños registren los avistamientos de animales: un diario de fauna crea un recuerdo duradero',
  ]},
  { type: 'h2', text: 'Consideraciones de salud para los niños' },
  { type: 'p', text: 'La profilaxis contra la malaria es esencial para los niños que viajan a Tanzania, Kenia y Ruanda. Consulta con tu médico o clínica de viajes con suficiente antelación: los niños tienen requisitos de dosificación específicos según el peso y algunos medicamentos profilácticos para adultos no son adecuados para los niños pequeños. El repelente de insectos con DEET debe aplicarse al amanecer y al anochecer, cuando los mosquitos son más activos. Los productos más seguros para los niños son los que tienen un 20-30 % de DEET, menor concentración que los productos para adultos pero igualmente eficaces.' },
  { type: 'p', text: 'La protección solar es fundamental. El sol ecuatorial a través de una escotilla abierta del techo del vehículo es intenso y los niños se queman rápidamente. Aplica crema solar SPF 50+ cada dos horas durante las excursiones y asegúrate de que los niños lleven mangas largas y sombreros de ala ancha durante las horas de mayor sol, de 10 de la mañana a 3 de la tarde. La hidratación también es importante: los niños deben beber al menos 1,5 litros de agua al día con el calor, lo que puede ser un reto cuando están concentrados en la fauna.' },
  { type: 'h2', text: 'Añadir Zanzíbar para familias' },
  { type: 'p', text: 'Zanzíbar es una excelente extensión familiar, especialmente las tranquilas playas de la costa norte de Nungwi y Kendwa donde el agua es bañable con cualquier marea. El Santuario de Tortugas de Isla Prisión, a 15 minutos en barca desde Stone Town, es enormemente popular entre los niños: puedes caminar entre ellas y dar de comer con la mano a tortugas gigantes de Aldabra, algunas de más de 100 años y de tamaño impresionante. Los tours de delfines en la costa sur son otro favorito familiar, aunque elige operadores responsables que no persigan ni acosen a los animales.' },
  { type: 'callout', text: 'Los niños que crecen con un recuerdo de safari son niños que entienden que los animales salvajes existen y son importantes, no como abstracciones en un documental sino como criaturas reales que han visto, olido y cuya presencia han sentido. Esa comprensión es un regalo que merece la pena planificar un viaje.' },
],

'ngorongoro-crater-guide': [
  { type: 'p', text: 'El Cráter del Ngorongoro es la caldera volcánica intacta más grande del mundo, un cuenco de 260 km² hundido 600 metros por debajo del borde del cráter circundante. En su interior viven 25.000 animales —leones, elefantes, hipopótamos, hienas, cebras, ñus, búfalos, flamencos y el rinoceronte negro en peligro crítico— en un ecosistema autónomo tan completo que casi ninguno de los animales lo abandona jamás. Visitar el Ngorongoro no es como visitar otros parques. Es como entrar en un anfiteatro natural donde las paredes son montañas boscosas y el escenario es uno de los más extraordinarios del mundo en materia de fauna salvaje.' },
  { type: 'h2', text: 'Geografía y formación' },
  { type: 'p', text: 'El Ngorongoro se formó hace aproximadamente 2,5 millones de años cuando un gran volcán —que se estima que era tan alto como el Kilimanjaro— se derrumbó hacia adentro tras una serie de erupciones. La caldera resultante tiene aproximadamente 18 km de anchura en su punto más ancho, rodeada de paredes boscosas que se elevan entre 400 y 600 metros sobre el fondo del cráter. El fondo en sí mismo contiene un complejo de hábitats: llanuras abiertas de hierba, bosques de acacias, el Bosque Lerai, el Pantano Gorigor y el Lago Magadi, un lago de soda poco profundo en la esquina suroeste que atrae a miles de flamencos.' },
  { type: 'h2', text: 'La fauna en el fondo del cráter' },
  { type: 'p', text: 'La densidad de fauna del Ngorongoro es extraordinaria, no porque el cráter contenga especies inusuales, sino porque la geografía contenida las concentra. Los leones están presentes en gran número, y las manadas del Ngorongoro son famosas: algunas de las manadas más grandes de África Oriental viven aquí, y los leones están tan habituados a los vehículos que puedes observarlos a distancias de dos a cinco metros. El pool genético de leones dentro del cráter está en gran parte aislado de las manadas exteriores, lo que ha creado algunas características físicas visibles en los leones locales, incluidas melenas inusualmente pobladas en los machos.' },
  { type: 'p', text: 'Los elefantes del cráter son principalmente toros grandes y viejos: los grupos familiares liderados por matriarcas tienden a moverse por el borde del cráter y hacia abajo por los bosques sobre el fondo. Los toros que permanecen en el fondo del cráter todo el año son algunos de los más impresionantes de África Oriental: antiguos, masivos, con enormes colmillos que representan décadas de vida protegida dentro del área de conservación. La Autoridad del Área de Conservación del Ngorongoro (NCAA) mantiene estrictas patrullas anticontrabando, y los resultados son visibles en el estado de los animales.' },
  { type: 'h2', text: 'El rinoceronte negro' },
  { type: 'p', text: 'Los aproximadamente 25 rinocerontes negros del Ngorongoro representan una de las poblaciones más importantes y más cuidadosamente protegidas de África Oriental. El rinoceronte negro está en peligro crítico: menos de 6.000 sobreviven en estado salvaje a nivel mundial, y la población del Ngorongoro se gestiona como una subpoblación genéticamente significativa. Los avistamientos no están garantizados, pero este es uno de los lugares más fiables de África para ver el rinoceronte negro en estado salvaje.' },
  { type: 'p', text: 'La mejor estrategia para ver rinocerontes es llegar al fondo del cráter a la hora de apertura (7:00 de la mañana) y dirigirse directamente a las fuentes de Ngoitokitok y la zona del pantano Mandusi en el fondo oriental del cráter, el territorio más consistente de los rinocerontes. Ten paciencia: los rinocerontes del Ngorongoro no están muy habituados a los vehículos y pueden alejarse rápidamente. Tener prismáticos hace una diferencia significativa: tu guía puede ver al rinoceronte desde lejos antes de acercarse para tener una mejor vista.' },
  { type: 'h2', text: 'Visitar el cráter: logística' },
  { type: 'p', text: 'El acceso al fondo del Cráter del Ngorongoro está estrictamente controlado por la NCAA. Los vehículos entran por la carretera de descenso de Seneto y salen por la carretera de ascenso de Lerai, en sentido único. Se permite un máximo de aproximadamente 500 vehículos al día en el fondo del cráter, y el cráter está cerrado a los vehículos desde el anochecer hasta el amanecer. Las excursiones en el fondo del cráter duran normalmente de cinco a seis horas, y la mayoría de los itinerarios asignan un día completo al Ngorongoro.' },
  { type: 'p', text: 'Todos los vehículos deben ser todoterrenos cerrados: no se permiten vehículos descapotados en el fondo del cráter (los laterales se pueden levantar, pero el techo debe poder cerrarse). Esta es una norma de seguridad para la fauna: los leones en el suelo del Ngorongoro están suficientemente cerca de los vehículos como para que un 4×4 de lados abiertos suponga un riesgo inaceptable. Los vehículos de tu operador cumplirán automáticamente esta norma si tienen licencia legítima.' },
  { type: 'tip', title: 'Día completo frente a medio día', text: 'Un medio día en el fondo del cráter no es suficiente. El Ngorongoro merece un día completo: llega a la apertura, pasa toda la mañana en las zonas principales de fauna, come en el estanque de hipopótamos de Ngoitokitok y explora el lago de flamencos del suroeste por la tarde. Salir antes de las 3 de la tarde significa perderse la actividad vespertina de los depredadores.' },
  { type: 'h2', text: 'El borde del cráter' },
  { type: 'p', text: 'El Área de Conservación del Ngorongoro se extiende mucho más allá del fondo del cráter. El propio borde del cráter se encuentra a aproximadamente 2.300 metros de altitud y es frío, neblinoso y boscoso: un contraste dramático con el cálido fondo de abajo. Los alojamientos en el borde ofrecen la extraordinaria experiencia de despertar en el bosque, salir a tu terraza y contemplar el cráter a través de una diferencia de altitud de 600 metros. En las mañanas despejadas, la vista desde el borde es una de las más extraordinarias de África: todo el anfiteatro natural extendido debajo de ti, con animales visibles con prismáticos en el fondo del cráter.' },
  { type: 'h2', text: 'Combinar el Ngorongoro con el Serengueti' },
  { type: 'p', text: 'Casi todos los itinerarios del Circuito Norte de Tanzania combinan el Ngorongoro con el Serengueti: los dos están separados por menos de 100 km y se complementan perfectamente. El Serengueti ofrece vastas llanuras abiertas y la Gran Migración; el Ngorongoro ofrece densidad contenida y el rinoceronte. Reserva un día completo para el cráter y al menos tres noches en el Serengueti para la combinación ideal. Algunos itinerarios incluyen el Lago Manyara o Tarangire antes de pasar a los parques principales: los circuitos de tres o cuatro parques en siete días son el formato estándar del Circuito Norte.' },
  { type: 'callout', text: 'Ninguna fotografía, ningún documental, ninguna descripción te prepara del todo para el momento en que tu vehículo desciende por la pared del cráter y el vasto fondo se despliega debajo de ti. El Ngorongoro no es un zoológico: los animales son salvajes, el espacio es real y la densidad de vida en ese cuenco de 260 km² es algo que la mente humana lucha por procesar hasta que estás dentro de él. Planifica al menos un día completo; dos días es mejor.' },
],

'serengeti-vs-masai-mara': [
  { type: 'p', text: 'El Serengueti y el Masái Mara son el mismo ecosistema: las mismas praderas, la misma migración, los mismos leones, los mismos ñus. Los separa la frontera entre Kenia y Tanzania, una línea trazada por administradores coloniales que la fauna ignora por completo. Pero se sienten como lugares diferentes, atraen a campamentos diferentes y recompensan a los visitantes de maneras distintas. Elegir entre ellos —o combinarlos— es una de las decisiones más debatidas en la planificación de safaris en África Oriental.' },
  { type: 'h2', text: 'Tamaño y escala' },
  { type: 'p', text: 'El Serengueti cubre 14.763 kilómetros cuadrados; el Masái Mara cubre 1.510 kilómetros cuadrados. El Serengueti es casi diez veces más grande. Esta diferencia de escala tiene implicaciones prácticas significativas. En el Serengueti, puedes conducir durante horas sin ver otro vehículo. En el Masái Mara, no puedes. El Mara es tan pequeño que la densidad de vehículos durante la temporada pico de migración —de julio a septiembre— puede alcanzar niveles que los viajeros experimentados de safari describen como genuinamente frustrantes.' },
  { type: 'p', text: 'El tamaño del Serengueti significa que tiene zonas distintas, cada una con diferentes características y tiempos de visita óptimos. El norte del Serengueti durante la temporada de cruces del Mara es más comparable al Masái Mara en términos de densidad de fauna y emoción. El Serengueti central a lo largo del año ofrece fauna residente fiable. El sur del Serengueti en la temporada de partos no tiene igual en ningún lugar. El corredor occidental durante los cruces del Grumeti en junio está en gran parte libre de multitudes y es extraordinario.' },
  { type: 'h2', text: 'Densidad de vehículos y masificación' },
  { type: 'p', text: 'Esta es la mayor debilidad del Masái Mara y la fortaleza subestimada del Serengueti. En los puntos de cruce populares del río Mara durante julio y agosto, no es raro ver veinte, treinta o cuarenta vehículos congregados alrededor de un solo punto de cruce: una pared de metal y rostros de turistas que puede reducir un momento sublime de fauna a un espectáculo inquietante.' },
  { type: 'p', text: 'El Serengueti tiene más regulaciones sobre la densidad de vehículos en los puntos de cruce más populares, pero más espacio para extenderse entre ellos. Más importante aún, el norte del Serengueti —en particular el Triángulo Lamai— tiende a tener menos vehículos que las zonas comparables del Masái Mara porque la aproximación requiere un largo viaje en coche o un vuelo chárter. Este filtro natural produce una experiencia más exclusiva en el lado tanzano para quienes la buscan.' },
  { type: 'h2', text: "Los conservancies privados: la ventaja de Kenia" },
  { type: 'p', text: 'El argumento más sólido para elegir Kenia son los conservancies privados adyacentes al Masái Mara. El Conservancy Naboisho, el Conservancy Olare Motorogi, el Conservancy Mara North y otros cubren cientos de kilómetros cuadrados de excelentes terrenos de caza que bordean la reserva nacional. En estos conservancies puedes conducir fuera de carretera (no permitido en ningún parque nacional de Tanzania), hacer excursiones nocturnas y safaris a pie con guardabosques armados. La baja densidad de campamentos significa muchos menos vehículos por kilómetro cuadrado que en la reserva nacional.' },
  { type: 'p', text: 'Para la fotografía de fauna y los encuentros íntimos, los conservancies del Mara ofrecen experiencias que los parques nacionales de Tanzania no pueden replicar legalmente. Una excursión nocturna en el Conservancy Naboisho —rastreando leopardos con un foco, viendo cómo salen los cerdos hormigueros, los servales y las civetas en la oscuridad— es una de las experiencias más emocionantes de África Oriental y simplemente no está disponible en el Parque Nacional del Serengueti.' },
  { type: 'table', headers: ['Factor', 'Serengueti', 'Masái Mara'], rows: [
    ['Tamaño', '14.763 km²', '1.510 km² (+ conservancies privados)'],
    ['Conducción fuera de carretera', 'No permitida', 'Permitida en conservancies privados'],
    ['Excursiones nocturnas', 'No permitidas en el parque nacional', 'Disponibles en conservancies'],
    ['Safaris a pie', 'Disponibles en concesiones privadas', 'Disponibles en conservancies'],
    ['Densidad de vehículos', 'Menor (con la elección correcta de zona)', 'Mayor en la reserva; menor en conservancies'],
    ['Tiempo de migración', 'Octubre-junio (la mayor parte del año)', 'Julio-septiembre (solo en el pico)'],
    ['Coste', 'Comparable al mismo nivel', 'Comparable al mismo nivel'],
  ]},
  { type: 'h2', text: 'La migración: ¿importa qué lado eliges?' },
  { type: 'p', text: 'Para los cruces del río Mara (julio-octubre), el lado tanzano (norte del Serengueti) ofrece los mismos cruces que el lado keniano (Masái Mara) pero con marginalmente menos vehículos en los puntos de cruce. Las manadas se mueven constantemente de un lado al otro de la frontera durante este período: un campamento en cualquiera de los dos lados te dará acceso a los cruces. La diferencia está en el campamento y la zona de conducción, no en la fauna.' },
  { type: 'p', text: 'Para cualquier otra fase de la migración —temporada de partos (enero-febrero), Grumeti (junio), las manadas de las llanuras del sur (diciembre)— Tanzania es la única opción. Estas fases no ocurren en Kenia, y los visitantes que solo han visto la temporada de cruces del Mara en agosto han visto un extraordinario capítulo de una historia de doce meses.' },
  { type: 'tip', title: 'Lo mejor de ambos', text: 'Un itinerario combinado Tanzania-Kenia —Serengueti y Ngorongoro seguido de un conservancy del Mara— es la opción más atractiva de África Oriental. El Serengueti te da escala, variedad y las manadas migratorias; el conservancy del Mara te da excursiones nocturnas fuera de carretera y un área de caza privada íntima. Presupuesta entre 10 y 14 días en total.' },
  { type: 'callout', text: 'Ambos son extraordinarios. El Serengueti es el destino más completo, más diverso y más espacioso. Los conservancies del Masái Mara ofrecen experiencias —excursiones nocturnas, conducción fuera de carretera, safaris a pie— que el parque nacional del Serengueti no puede proporcionar legalmente. Elige según lo que más valores, o combínalos. El ecosistema no sabe que la frontera existe, y a los ñus definitivamente no les importa.' },
],

'7-day-tanzania-safari-itinerary': [
  { type: 'p', text: 'Siete noches en Tanzania son suficientes para experimentar el Circuito Norte completo y volver genuinamente cambiado por lo que has visto. El Circuito Norte conecta cuatro de los mejores parques de Tanzania en un bucle geográfico lógico: Tarangire, Lago Manyara, el Serengueti y el Cráter del Ngorongoro. Cada parque añade algo que los demás no tienen. Juntos forman el itinerario de fauna de África Oriental más completo.' },
  { type: 'h2', text: 'La ruta: visión general del Circuito Norte' },
  { type: 'p', text: 'Todos los itinerarios del Circuito Norte comienzan y terminan en Arusha, la capital del safari de Tanzania y puerta de entrada a los parques del norte. El Aeropuerto Internacional de Kilimanjaro (JRO), a 45 km de Arusha, recibe vuelos directos desde Nairobi, Addis Abeba, Ámsterdam, Dubái y Londres, entre otros. Desde Arusha, el circuito fluye al oeste hacia Tarangire, luego al norte hacia el Lago Manyara, luego más al oeste hacia el Serengueti y finalmente al sureste hacia el Ngorongoro antes de regresar a Arusha.' },
  { type: 'h2', text: 'Itinerario día a día' },
  { type: 'table', headers: ['Día', 'Ubicación', 'Actividad', 'Alojamiento'], rows: [
    ['Día 1', 'Arusha / Tarangire', 'Llegar a JRO; traslado a Tarangire (2,5 h); excursión vespertina', 'Campamento/alojamiento en Tarangire'],
    ['Día 2', 'Tarangire', 'Excursiones de día completo; elefantes, baobabs, fauna del río Tarangire', 'Campamento/alojamiento en Tarangire'],
    ['Día 3', 'Lago Manyara', 'Excursión matutina Tarangire; tarde en el Lago Manyara (flamencos, leones trepadores)', 'Alojamiento en Manyara'],
    ['Día 4', 'En ruta al Serengueti', 'Excursión matutina; picnic en el borde del Ngorongoro; llegar al Serengueti por la tarde', 'Campamento en el Serengueti central'],
    ['Día 5', 'Serengueti', 'Excursiones de día completo; leones residentes, leopardos, guepardos; actividad según la migración', 'Campamento en el Serengueti central'],
    ['Día 6', 'Serengueti / Ngorongoro', 'Excursión matutina en el Serengueti; traslado al borde del Ngorongoro (3 h)', 'Alojamiento en el borde del Ngorongoro'],
    ['Día 7', 'Cráter del Ngorongoro', 'Día completo de descenso al cráter; Cinco Grandes; rinoceronte negro; picnic en la laguna de hipopótamos', 'Alojamiento en el borde del Ngorongoro'],
    ['Día 8', 'Salida', 'Excursión/paseo matutino cerca del borde; traslado Arusha; salida desde JRO', '–'],
  ]},
  { type: 'h2', text: 'Días 1-2: Parque Nacional Tarangire' },
  { type: 'p', text: 'Tarangire es la joya subestimada del Circuito Norte. La mayoría de los visitantes le dedican poco tiempo en favor de más tiempo en el Serengueti: un error. La estación seca (junio-octubre) trae una de las concentraciones de elefantes más espectaculares de África: cientos de elefantes se congregan a lo largo del río Tarangire, incluidos enormes toros con grandes colmillos, grupos familiares liderados por matriarcas y juveniles jugando en el barro del río. El paisaje de Tarangire también es distintivo: baobabs antiguos, matorral denso y largas vistas sobre el pantano de Tarangire.' },
  { type: 'p', text: 'Tarangire también tiene excelentes poblaciones de depredadores: leones, leopardos y guepardos están todos presentes, y el parque es uno de los mejores de Tanzania para la avifauna: más de 550 especies, incluido el inseparable de cuello amarillo, un endémico de Tarangire, y grandes colonias de barbetos rojo y amarillo que anidan en los baobabs. Reserva dos días completos aquí.' },
  { type: 'h2', text: 'Día 3: Parque Nacional del Lago Manyara' },
  { type: 'p', text: 'El Lago Manyara es un parque compacto con un impacto desproporcionado. El lago en sí —un lago de soda alcalino poco profundo en la base de la pared del Valle del Rift— atrae a enormes bandadas de flamencos, pelícanos y otras aves acuáticas. El parque también es famoso por sus leones trepadores de árboles: manadas que descansan en las horquillas de los árboles de fiebre, un comportamiento poco comprendido pero observado de forma fiable. El parque puede cubrirse en medio día, lo que lo hace ideal como parada de camino entre Tarangire y el Serengueti.' },
  { type: 'h2', text: 'Días 4-5: El Serengueti' },
  { type: 'p', text: 'El Serengueti es el corazón del itinerario y merece todo el tiempo que puedas darle. En un circuito de siete noches, dos o tres noches en el Serengueti significa dos o tres días de excursiones, suficiente para ver leones, leopardos, guepardos, elefantes, búfalos, jirafas, cebras y docenas de otras especies. La ubicación de la migración dentro del Serengueti depende enteramente de la época del año: manadas de parto en el sur (enero-febrero), manadas centrales moviéndose al norte (marzo-mayo), cruces del corredor occidental (junio), o cruces del Mara al norte (julio-octubre).' },
  { type: 'tip', title: 'Volar frente a conducir', text: 'Volar desde Arusha directamente a una pista de aterrizaje del Serengueti (45 minutos) y conducir de regreso por el Ngorongoro ahorra un día completo de conducción y ofrece una extraordinaria vista aérea del ecosistema. Este enfoque de entrada volando y salida conduciendo es la forma más eficiente de maximizar el tiempo de avistamiento de fauna en un itinerario de siete días.' },
  { type: 'h2', text: 'Días 6-7: Cráter del Ngorongoro' },
  { type: 'p', text: 'El Cráter del Ngorongoro es el capítulo final perfecto. Tras la vasta inmensidad del Serengueti, el drama contenido del cráter —25.000 animales visibles en todas las direcciones, leones cazando a corta distancia, el rinoceronte negro en la lejanía— proporciona un registro emocional completamente diferente. Pasa un día completo en el fondo del cráter: llega a la hora de apertura, trabaja las zonas principales de fauna durante la mañana, haz un picnic en la laguna de hipopótamos para comer y pasa la tarde en el lago de flamencos y con la actividad vespertina de los depredadores antes de ascender por la pared del cráter a las 4 de la tarde.' },
  { type: 'callout', text: 'Siete días en Tanzania son suficientes para transformarte. No son suficientes para verlo todo —eso no es posible en toda una vida de regresos—, pero sí son suficientes para entender por qué las personas que visitan Tanzania por primera vez casi siempre empiezan a planificar su segundo viaje antes de haber aterrizado de vuelta a casa.' },
],

'budget-safari-tanzania': [
  { type: 'p', text: 'Tanzania tiene fama de safaris caros, y es parcialmente merecida. Las tasas de los parques gubernamentales por sí solas son de las más altas de África. Pero un safari genuinamente asequible en Tanzania es posible si entiendes qué impulsa el coste y qué decisiones te dan la mejor experiencia de fauna por dólar gastado. No te quedarás en un campamento de lujo con presupuesto ajustado. Seguirás viendo el Serengueti, el Cráter del Ngorongoro y una fauna que es tan extraordinaria como cualquier cosa vista desde un campamento de 1.000 dólares la noche.' },
  { type: 'h2', text: '¿Por qué son caros los safaris en Tanzania?' },
  { type: 'p', text: 'La Autoridad de Parques Nacionales de Tanzania (TANAPA) cobra 82 dólares por adulto y día en el Serengueti. Añade la tarifa del Área de Conservación del Ngorongoro (80 dólares), la tarifa de servicio del cráter (300 dólares por vehículo y descenso al cráter) y las tarifas de los vehículos (40-60 dólares por vehículo, parque y día), y la parte gubernamental de tu coste de safari rápidamente alcanza los 200-250 dólares por persona y día antes de tener en cuenta tu guía, vehículo y alojamiento. Estas tarifas son innegociables y van a la conservación: son las mismas para los viajeros económicos y de lujo por igual.' },
  { type: 'p', text: 'El alojamiento es donde las estrategias de presupuesto tienen el mayor impacto. La diferencia entre un safari de acampada (compartir una tienda comedor con otros viajeros) y un alojamiento de lujo es de 100 a más de 1.000 dólares por noche por persona. Un safari de acampada económico utiliza campings públicos dentro de los parques nacionales, un cocinero que prepara comidas sencillas pero nutritivas y un vehículo 4×4 compartido entre cuatro o seis viajeros. La fauna vista desde ese vehículo es idéntica a la fauna vista desde la excursión privada de un campamento de lujo.' },
  { type: 'h2', text: 'Niveles de safari con presupuesto ajustado' },
  { type: 'table', headers: ['Nivel', 'Coste por persona y día', 'Alojamiento', 'Vehículo'], rows: [
    ['Acampada económica', '150-200 $', 'Camping público, tienda básica, instalaciones compartidas', '4×4 compartido (4-6 personas)'],
    ['Presupuesto medio', '200-300 $', 'Alojamiento económico o campamento en tienda semipermanente', '4×4 compartido (4-6 personas)'],
    ['Gama media', '300-450 $', 'Buen alojamiento de gama media con baño privado', 'Compartido o grupo pequeño privado'],
    ['Gama media alta', '450-700 $', 'Campamento de calidad, mejores comidas, grupo más pequeño', 'Vehículo privado posible'],
  ]},
  { type: 'h2', text: 'La ventaja de la temporada verde' },
  { type: 'p', text: 'Abril y mayo —la temporada de lluvias largas— es la temporada baja más significativa de Tanzania. Las tarifas de los alojamientos bajan un 20-40 %, algunos campamentos cierran por completo y los parques están sustancialmente más tranquilos. La fauna sigue siendo excelente: los depredadores son activos todo el año, la vegetación es exuberante y fotogénica y la avifauna alcanza su máximo cuando las especies migratorias europeas se unen a los residentes. La contrapartida son los caminos embarrados (un 4×4 los maneja, pero las excursiones pueden ser más lentas) y el ocasional aguacero vespertino.' },
  { type: 'p', text: 'Noviembre es otro mes de buen valor: las lluvias cortas comienzan pero suelen ser breves chubascos diarios en lugar de las lluvias sostenidas de abril-mayo. Los avistamientos de fauna son excelentes, los parques están tranquilos y los precios son notablemente más bajos que en los períodos pico de junio-octubre y enero-febrero. Para los viajeros con presupuesto ajustado, elegir abril-mayo o noviembre ofrece ahorros significativos sin una compensación importante en la fauna.' },
  { type: 'h2', text: 'Safaris en grupo frente a privados' },
  { type: 'p', text: 'Unirse a un safari en grupo pequeño es la forma más efectiva de reducir los costes por persona en un safari en Tanzania. Cuando cuatro o seis viajeros comparten un vehículo, la parte por persona del alquiler del vehículo, las tarifas del guía y el combustible cae significativamente. Los operadores de safari en grupo de calidad diseñan sus vehículos y rutas para grupos de cuatro a seis personas: el vehículo tiene seis asientos con buenas vistas y el tamaño del grupo es lo suficientemente pequeño como para seguir siendo social y flexible.' },
  { type: 'p', text: 'La contrapartida es el horario. Un safari en grupo sigue fechas de salida fijas e itinerarios fijos. No puedes parar una hora extra en un avistamiento de leones si el grupo está listo para moverse. No puedes ajustar la ruta en función de los movimientos de las manadas en tiempo real. Para los visitantes primerizos con fechas de viaje flexibles y enfoque en el presupuesto, esta contrapartida merece totalmente la pena. Para los visitantes que regresan o los que tienen prioridades específicas de fauna, un vehículo privado vale la prima.' },
  { type: 'tip', title: 'Reserva directamente con operadores tanzanos', text: 'Reservar directamente con un operador tanzano en lugar de hacerlo a través de un agente de viajes extranjero elimina el recargo del 15-25 % del agente extranjero. Un operador con sede en Arusha que cotiza 2.000 dólares por un safari de 7 días suele ofrecer la misma calidad o mejor que un agente del Reino Unido que cotiza 2.500 dólares por el mismo producto. Investiga, lee reseñas y reserva localmente.' },
  { type: 'h2', text: 'Coste de muestra de un safari de 7 días con presupuesto ajustado' },
  { type: 'p', text: 'Un safari de acampada de 7 noches por el Circuito Norte para una persona, compartiendo vehículo con otros tres viajeros, viajando en mayo (temporada verde) por Tarangire, Manyara, Serengueti y Ngorongoro, con un operador con sede en Arusha, costará normalmente entre 1.800 y 2.400 dólares incluyendo todas las tasas de los parques, comidas, acampada y guía. Añade entre 1.000 y 1.600 dólares para los vuelos de ida y vuelta desde Londres u otro hub europeo importante en la misma temporada (baja demanda = tarifas más bajas). Coste total del viaje: entre 2.800 y 4.000 dólares por persona, mucho menos de los 10.000 dólares que mucha gente asume que es el mínimo para un safari en Tanzania.' },
  { type: 'h2', text: 'A qué renuncias en un safari económico' },
  { type: 'ul', items: [
    'Vehículo privado: compartes con otros viajeros y no siempre puedes parar cuando quieres',
    'Alojamiento de lujo: los campings públicos tienen instalaciones básicas compartidas; la comida es sencilla pero suficiente',
    'Ambiente de campamento en el bush: la magia de despertar en un campamento privado exclusivo rodeado de fauna es una experiencia de lujo',
    'Flexibilidad: las salidas en grupo siguen horarios e itinerarios fijos',
    'Ratio de personal: los campamentos de lujo tienen varios empleados por huésped; las operaciones económicas son más ajustadas',
  ]},
  { type: 'callout', text: 'Un safari económico en Tanzania no es un safari inferior. Al león del Serengueti no le importa en qué vehículo llegaste. La luz del amanecer sobre el Cráter del Ngorongoro es igualmente extraordinaria tanto si dormiste en una tienda de 50 dólares como en una habitación de 500 dólares. A lo que renuncias es a la comodidad y la flexibilidad: lo que ganas es acceso a uno de los mayores espectáculos de fauna de la Tierra sin pasar una década ahorrando para ello.' },
],

'chimpanzee-trekking-tanzania': [
  { type: 'p', text: 'Los parques occidentales de Tanzania —Gombe Stream y Mahale Mountains— ofrecen el mejor trekking de chimpancés del mundo. Estos son los lugares donde comenzó en 1960 la investigación pionera de Jane Goodall sobre la inteligencia y el comportamiento social de los chimpancés, una investigación que cambió fundamentalmente nuestra comprensión de lo que significa ser humano. Hoy en día, hacer trekking para encontrar comunidades de chimpancés habituadas en el bosque es uno de los encuentros con fauna salvaje más profundamente emotivos de África, y uno de los más pasados por alto, situado muy lejos del circuito turístico mayoritario.' },
  { type: 'h2', text: 'Parque Nacional Gombe Stream' },
  { type: 'p', text: 'Gombe es el parque nacional más pequeño de Tanzania, con solo 52 kilómetros cuadrados de bosque empinado a lo largo de la orilla oriental del lago Tanganika. También es el más históricamente significativo para la investigación de la vida salvaje. Jane Goodall llegó aquí en 1960, y la estación de investigación que estableció sigue monitoreando las comunidades de chimpancés décadas después. La comunidad de chimpancés de Kasakela, el grupo de chimpancés salvajes más estudiado del mundo, vive en el bosque sobre la estación de investigación y puede ser rastreado diariamente por los trekkers.' },
  { type: 'p', text: 'Los chimpancés de Gombe son los más habituados de África, resultado directo de seis décadas de presencia humana continua del equipo de investigación. Esto significa encuentros más cercanos y más tranquilos que en casi cualquier otro lugar. Los chimpancés pueden caminar a dos o tres metros de tu grupo de trekking, sentarse en árboles directamente encima de ti y mostrar comportamientos sociales naturales —acicalamiento, forrajeo, despliegues de dominancia de machos— sin perturbación significativa por la presencia humana.' },
  { type: 'h2', text: 'Parque Nacional de las Montañas Mahale' },
  { type: 'p', text: 'Mahale es todo lo que Gombe no es: remoto, vasto (1.613 kilómetros cuadrados), dramáticamente hermoso y prácticamente libre de otros turistas. Las Montañas Mahale se elevan abruptamente desde la orilla del lago Tanganika —el segundo lago más profundo del mundo— y el bosque que sube por esas laderas alberga a aproximadamente 1.000 chimpancés. El grupo M, la comunidad más habituada, es rastreado diariamente desde un pequeño número de campamentos exclusivos en la orilla del lago.' },
  { type: 'p', text: 'Llegar a Mahale es parte de la aventura. No hay acceso por carretera: se llega al parque ya sea en vuelo chárter hasta la pista de aterrizaje de Mahale o en barca desde Kigoma (un viaje de 6 a 8 horas en lancha motora). Esta inaccesibilidad mantiene el número de visitantes muy bajo: en cualquier día dado, menos de 20 personas hacen trekking en Mahale. Los encuentros con chimpancés se sienten genuinamente remotos e intactos de una manera que Gombe, con su proximidad a la estación de investigación, no puede replicar del todo.' },
  { type: 'h2', text: 'La experiencia del trekking' },
  { type: 'p', text: 'El trekking en Gombe y Mahale sigue el mismo patrón. Los guías con conocimiento diario de la ubicación de la comunidad de chimpancés llevan a los trekkers al bosque al amanecer. Los rastreadores que siguieron a los chimpancés la tarde anterior conocen su ubicación de anidamiento, el punto de partida de la búsqueda de la mañana. El trekking por el bosque puede durar desde treinta minutos hasta cuatro horas dependiendo de adónde se hayan desplazado los chimpancés durante la noche.' },
  { type: 'p', text: 'Cuando se localiza a la comunidad de chimpancés, tu guía coloca al grupo a una distancia respetuosa. Pasas una hora con el grupo, la misma norma de protección que el trekking de gorilas. La experiencia de estar con chimpancés salvajes es fundamentalmente diferente a la de los gorilas: los chimpancés son más ruidosos, más rápidos, más maníacos y más activamente curiosos. Donde un encuentro con un gorila es a menudo profundamente tranquilo y contemplativo, un encuentro con chimpancés es enérgico y a veces abrumador.' },
  { type: 'tip', title: 'Protocolos de salud', text: 'Los chimpancés comparten aproximadamente el 98,7 % del ADN humano y son muy susceptibles a los virus respiratorios humanos. Tanto Gombe como Mahale aplican estrictas normas sanitarias: cualquier persona con síntomas de resfriado o gripe está excluida del trekking. Lleva una mascarilla cuando estés a menos de 10 metros de los chimpancés. La edad mínima para el trekking es de 15 años.' },
  { type: 'h2', text: 'Gombe frente a Mahale: ¿cuál elegir?' },
  { type: 'table', headers: ['Factor', 'Gombe', 'Mahale'], rows: [
    ['Acceso', 'Lancha rápida desde Kigoma (1-2 h)', 'Vuelo chárter o larga barca desde Kigoma'],
    ['Tamaño', 'Muy pequeño (52 km²)', 'Grande (1.613 km²)'],
    ['Grupos habituados', 'Comunidad Kasakela', 'Grupo M (y otros)'],
    ['Visitantes diarios', 'Hasta 20', 'Menos de 15'],
    ['Coste', 'Más asequible', 'Más caro (campamentos remotos)'],
    ['Playa/lago', 'Buena natación en la playa de Gombe', 'Excepcional: orilla del lago prístina'],
    ['Otra fauna', 'Babuinos de olivo, colobo rojo', 'Colobo rojo, otras especies forestales'],
    ['Alojamiento', 'Solo básico a gama media', 'Campamentos de lago de gama media a lujo'],
  ]},
  { type: 'h2', text: 'Cómo añadir los parques occidentales a tu itinerario en Tanzania' },
  { type: 'p', text: 'Gombe y Mahale no se combinan fácilmente con el Circuito Norte en un solo itinerario: la logística requiere volar a Kigoma (desde Dar es Salaam o Arusha) y luego acceder a los parques en barca. La mayoría de los visitantes eligen entre el circuito norte (Serengueti, Ngorongoro, Tarangire) o los parques occidentales, no ambos. Un itinerario dedicado a los parques occidentales de cinco a siete días —Gombe más Mahale más la histórica ciudad ferroviaria de Kigoma— es una experiencia de safari profundamente gratificante para quienes ya han hecho el Circuito Norte.' },
  { type: 'callout', text: 'Estar en el bosque mientras una familia de chimpancés salvajes pasa por los árboles encima de ti —deteniéndose, observando, continuando— no es simplemente un encuentro con la fauna salvaje. Es una confrontación con la delgada frontera entre especies. Jane Goodall lo entendió en 1960. Los visitantes que hacen el viaje a Gombe o Mahale lo entienden ahora. Esta es la experiencia más subestimada de Tanzania.' },
],

'luxury-safari-tanzania': [
  { type: 'p', text: 'Un safari de lujo en Tanzania no se define por el número de hilos de las sábanas o las cartas de menú. Se define por el acceso: acceso a concesiones exclusivas donde no operan otros vehículos, acceso a guías expertos con décadas de conocimiento específico del parque, acceso a experiencias —cenas privadas en el bush, vuelos en globo al amanecer, paseos con ancianos maasai— que simplemente no existen en los alojamientos estándar. Cuando se hace bien, un safari de lujo en Tanzania es la mejor experiencia de fauna disponible en cualquier parte de la Tierra.' },
  { type: 'h2', text: 'Qué significa realmente el lujo en safari' },
  { type: 'p', text: "La palabra 'lujo' se usa sin parar en el marketing de safaris. Todo campamento con una piscina se llama a sí mismo de lujo. Las distinciones significativas en un auténtico safari de lujo en Tanzania son operativas, no cosméticas. Un vehículo privado y un guía —solo para tu grupo— son la base. Sin ellos, estás a merced de un horario compartido. Las excursiones nocturnas, que requieren operar en una concesión privada o conservancy fuera de las normas de los parques nacionales, están a menudo reservadas para los campamentos de lujo porque solo ellos tienen el acceso exclusivo a la tierra." },
  { type: 'p', text: 'El tamaño del campamento es el segundo factor definitorio. Los mejores campamentos de lujo en Tanzania admiten un máximo de ocho a dieciséis huéspedes. A esta escala, cada excursión está genuinamente poco concurrida, los guías conocen a cada huésped habitual por su nombre y la experiencia de despertar en un lugar salvaje —sin extraños en el desayuno, sin competencia por el mejor asiento del vehículo— se siente como lo que era el safari antes de que el turismo masivo lo complicara.' },
  { type: 'h2', text: 'Uso exclusivo y concesiones privadas' },
  { type: 'p', text: 'Los parques nacionales de Tanzania son públicos: cualquier operador con licencia puede conducir en ellos. Pero más allá de los límites del parque nacional, algunos operadores tienen concesiones privadas exclusivas: grandes bloques de tierra donde son el único vehículo, el único campamento, la única presencia humana. Estas concesiones privadas permiten la conducción fuera de carretera, las excursiones nocturnas, los safaris a pie y una exclusividad que ningún parque nacional puede ofrecer legalmente.' },
  { type: 'p', text: 'Las concesiones privadas que bordean el Serengueti, especialmente en las zonas norte cerca del río Mara, son algunas de las mejores áreas de fauna de África Oriental. La misma migración que pasa por el parque nacional también pasa por estas concesiones, pero la observas desde un vehículo que puede salir de la pista para seguir a una manada de perros salvajes en lugar de tener que quedarse en la carretera mientras la manada desaparece entre los matorrales.' },
  { type: 'h2', text: 'Experiencias de lujo emblemáticas en Tanzania' },
  { type: 'ul', items: [
    'Safari en globo aerostático sobre el Serengueti al amanecer: un vuelo de 60-90 minutos sobre las manadas migratorias, seguido de un desayuno con champán en el bush en las llanuras',
    'Cena privada en el bush: tu campamento monta una mesa para dos bajo las estrellas en un lugar secreto; tu guía y un guardabosques os acompañan por seguridad',
    'Safari a pie con un guía experto: abandonar el vehículo y rastrear fauna a pie cambia cada input sensorial y cada elemento de la experiencia',
    'Excursiones nocturnas en una concesión privada: rastrear leopardos, hienas, cerdos hormigueros y especies más pequeñas nocturnas que son invisibles en las excursiones diurnas',
    'Visita cultural a una comunidad maasai genuina: no una actuación, sino una introducción guiada facilitada por una comunidad con una larga relación con tu campamento',
    'Acampada volante: pasar una noche en un campamento temporal en el bush, durmiendo bajo las estrellas con solo una lona entre tú y la noche africana',
  ]},
  { type: 'h2', text: 'El safari en globo' },
  { type: 'p', text: 'El safari en globo sobre el Serengueti es una de las experiencias de lujo más icónicas de África Oriental. Antes del amanecer, te llevan al sitio de lanzamiento, subes a la cesta del globo con un grupo de ocho a doce pasajeros y te elevas silenciosamente por los aires mientras el Serengueti se vuelve dorado debajo de ti. El vuelo dura entre sesenta y noventa minutos, flotando a baja altitud sobre las llanuras y el bosque ribereño. La fauna de abajo incluye lo que sea que la migración haya colocado debajo de ti, lo que en julio y agosto puede significar volar directamente sobre decenas de miles de ñus.' },
  { type: 'p', text: 'La experiencia termina con un desayuno completo servido en mesas plegables en el bush, con champán independientemente de la hora. Es teatral, ciertamente, pero también genuinamente hermoso de una manera que las fotografías no pueden capturar. El silencio del globo en vuelo, interrumpido solo por el ocasional soplete de gas y los sonidos de las llanuras de abajo, es diferente a cualquier otra experiencia aérea.' },
  { type: 'h2', text: 'Costes del safari de lujo' },
  { type: 'p', text: 'Los auténticos safaris de lujo en Tanzania cuestan entre 700 y 1.500 dólares por persona y noche, todo incluido. Este rango cubre los campamentos privados de alta calidad con vehículos privados en el extremo inferior, y los campamentos de concesión privada ultra exclusivos con todas las experiencias concebibles incluidas en el extremo superior. El safari en globo es normalmente un coste adicional de entre 500 y 600 dólares por persona. Un itinerario de lujo de 7 noches costará entre 5.000 y 12.000 dólares por persona en destino, excluyendo los vuelos internacionales.' },
  { type: 'tip', title: 'Valor frente a precio', text: 'El campamento de lujo que cobra 1.500 dólares por noche no es necesariamente mejor que el que cobra 800. Las métricas clave son la exclusividad de la concesión, la calidad del guía, el tamaño del grupo (cuanto más pequeño, siempre mejor) y las actividades específicas incluidas. Un campamento de 800 dólares por noche en una concesión exclusiva con un excelente guía naturalista superará a un campamento de 1.500 dólares en una zona concurrida del parque.' },
  { type: 'callout', text: "El mercado de safaris de lujo de Tanzania ha sido refinado durante décadas por operadores que entienden que la mejor experiencia no es la más elaborada, sino la más enfocada. Vehículo privado. Guía experto. Campamento íntimo. La ubicación correcta en el momento correcto del año. Todo lo demás es teatro." },
],

'safari-photography-tips': [
  { type: 'p', text: 'Has pasado un año planificando, meses ahorrando y miles de dólares para estar en uno de los entornos fotográficamente más extraordinarios de la Tierra. La diferencia entre volver a casa con imágenes que hacen suspirar a la gente e imágenes que parecen cualquier otra instantánea de safari no es tu cámara: es tu comprensión de la luz, el momento y los desafíos técnicos específicos de la fotografía de fauna desde un vehículo en movimiento bajo la dura y contrastada luz africana.' },
  { type: 'h2', text: 'Conceptos básicos de cámara y objetivo' },
  { type: 'p', text: 'El equipo más importante para la fotografía de safari es tu objetivo, no el cuerpo de la cámara. Un objetivo que alcance los 400 o 500 mm es el mínimo para llenar el encuadre con leones, leopardos y otra fauna a las distancias típicas del safari. El Canon RF 100-500 mm, el Nikon Z 100-400 mm, el Sony 100-400 mm GM y el Sigma/Tamron 150-600 mm son excelentes objetivos de safari. Los fotógrafos con presupuesto ajustado pueden lograr excelentes resultados con cámaras sin espejo como la Sony a6700 o la Fujifilm XT-5 combinadas con un teleobjetivo adaptado.' },
  { type: 'p', text: 'El cuerpo de la cámara importa menos que tu objetivo, pero las modernas cámaras sin espejo han transformado la fotografía de safari con un excepcional autoenfoque continuo (seguimiento de sujeto), altas cadencias de disparo (15-30 fotogramas por segundo) y un extraordinario rendimiento a ISO alto que permite imágenes limpias con la escasa luz del amanecer cuando los depredadores son más activos. Sony, Canon y Nikon producen todas cámaras sin espejo para safari en una gama de precios.' },
  { type: 'h2', text: 'Configuración de la cámara para fauna salvaje' },
  { type: 'table', headers: ['Situación', 'Modo', 'Configuración recomendada'], rows: [
    ['Animales en movimiento rápido (corriendo)', 'Prioridad de obturador', 'Obturador: 1/1.000 s o más; ISO automático; AF continuo'],
    ['Depredador estático', 'Prioridad de apertura', 'f/5,6-f/8; ISO automático; AF continuo'],
    ['Poca luz al amanecer/anochecer', 'Manual o ISO automático', 'Obturador: 1/250 s o más; máx. f/4-f/5,6; ISO hasta 6.400'],
    ['Pájaros en vuelo', 'Prioridad de obturador', 'Obturador: 1/2.000 s o más; modo de seguimiento AF; ráfaga'],
    ['Paisaje amplio', 'Prioridad de apertura', 'f/8-f/11; ISO bajo; filtro polarizador si está disponible'],
  ]},
  { type: 'h2', text: 'Las horas doradas' },
  { type: 'p', text: 'El concepto fotográfico más importante en safari es simple: la calidad de la luz, no la proximidad al animal, determina tus mejores imágenes. La hora después del amanecer y la hora antes del atardecer —las horas doradas— ofrecen una luz cálida, direccional y favorecedora que transforma incluso a un león estático en una imagen cinematográfica. El sol de mediodía crea una luz cenital dura y poco favorecedora con sombras pesadas.' },
  { type: 'p', text: 'Esto se alinea perfectamente con la logística del safari. Las excursiones al amanecer, que comienzan a las 6:00-6:30 de la mañana, capturan la hora dorada además del período más activo de los depredadores. Las excursiones vespertinas de las 3:30-4:00 de la tarde te posicionan en el campo para la hora dorada previa al atardecer. El período de mediodía —cuando la mayoría de los campamentos tienen almuerzo, período de descanso y siesta vespertina— coincide con la luz fotográfica menos productiva. Usa ese descanso bien y vuelve al campo para el oro de la tarde.' },
  { type: 'h2', text: 'Disparar desde el vehículo' },
  { type: 'p', text: 'El vehículo de safari es tu plataforma fotográfica, y usarlo correctamente marca una diferencia dramática en la nitidez de la imagen. La vibración del motor es el enemigo de las imágenes nítidas: apaga el motor en el momento en que te detengas en un avistamiento y asegúrate de que tu guía sepa que debe hacerlo. Un motor en marcha a 400 mm crea desenfoque visible incluso a velocidades de obturador rápidas.' },
  { type: 'p', text: 'El saco de arena es el mejor amigo del fotógrafo de safari. Colocado sobre el borde de la ventanilla (o el borde de la escotilla abierta del techo en un vehículo con techo emergente), un saco de arena absorbe la vibración y proporciona una plataforma estable y ajustable en ángulo para tu objetivo. Es más sencillo, más versátil y más eficaz que un monópode o cualquier otro sistema montado en el vehículo. Lleva uno, o pide a tu operador que lo proporcione: muchos operadores de calidad los llevan.' },
  { type: 'tip', title: 'Dispara al nivel de los ojos cuando sea posible', text: "Los retratos de fauna más atractivos se toman al nivel de los ojos del animal, no desde arriba. Esto a menudo significa disparar desde la posición sentada a través de la ventanilla en lugar de ponerse de pie a través de la escotilla del techo. Un león fotografiado al nivel de sus ojos desde una ventanilla, con el fondo desenfocado gracias a una apertura amplia, casi siempre supera al mismo león fotografiado desde arriba a través del techo." },
  { type: 'h2', text: 'Principios de composición para safari' },
  { type: 'ul', items: [
    "Regla de los tercios: coloca el ojo del animal en una intersección de la cuadrícula, no en el centro del encuadre",
    "El fondo importa: comprueba qué hay detrás del animal antes de presionar el obturador: un vehículo u otro turista arruina una foto que de otro modo sería excelente",
    "Incluye el hábitat: un león llenando todo el encuadre es impresionante; un león en el contexto del paisaje del Serengueti cuenta una historia",
    "Espacio para el movimiento: deja espacio en el encuadre en la dirección en que el animal mira o se mueve",
    "Paciencia sobre cantidad: esperar el momento adecuado —un bostezo, un giro de cabeza, una mirada directa— produce imágenes mucho mejores que disparar en ráfaga a todo lo que se mueve",
  ]},
  { type: 'h2', text: 'Gestionar el polvo' },
  { type: 'p', text: 'El polvo es la mayor amenaza práctica para tu equipo fotográfico en safari. Las excursiones en la estación seca generan polvo significativo y hasta pequeñas cantidades dentro de una cámara o sobre un sensor crean problemas. Mantén las cámaras en una bolsa de cámara o bolsa estanca cuando no las estés usando. Cambia los objetivos dentro del vehículo con las ventanillas cerradas, trabajando rápidamente. Lleva un soplador y un paño para el objetivo para la limpieza diaria. Considera un filtro UV en tu objetivo más usado para proteger el elemento frontal del impacto de la arena.' },
  { type: 'callout', text: 'Las mejores fotografías de safari no se toman con las mejores cámaras: las toman los fotógrafos que se levantaron temprano, entendieron la luz, respetaron el comportamiento de los animales, esperaron pacientemente el momento decisivo y tuvieron un guía lo suficientemente hábil como para posicionar el vehículo correctamente. El equipo importa, pero no tanto como estar en el lugar correcto en el momento correcto con el conocimiento adecuado.' },
],

'ruaha-national-park-guide': [
  { type: 'p', text: 'Ruaha es el parque nacional más grande de Tanzania con 20.226 kilómetros cuadrados, y uno de los menos visitados de los lugares de fauna significativos de África Oriental. Esto no se debe a que Ruaha sea de segunda categoría. Se debe a que Ruaha es remoto, requiere un vuelo desde Dar es Salaam o Arusha y tiene solo una fracción de la capacidad de campamentos de los parques del Circuito Norte. Para los que hacen el viaje, Ruaha produce de forma consistente lo que los viajeros experimentados de safari describen como la mejor experiencia de fauna de Tanzania, quizás de África.' },
  { type: 'h2', text: 'Por qué Ruaha es extraordinario' },
  { type: 'p', text: 'Ruaha alberga un estimado del 10 % de la población de leones restante del mundo: miles de leones concentrados en un parque que recibe relativamente pocos turistas. Las manadas de leones aquí son grandes, los machos son imponentes y la densidad de interacciones depredador-presa en el Gran Río Ruaha rivaliza con cualquier cosa en el Serengueti. Pero los leones de Ruaha no han sido habituados al mismo grado que las poblaciones del Serengueti: son más salvajes, menos predecibles y más emocionantes de encontrar por eso mismo.' },
  { type: 'p', text: "La población de elefantes de Ruaha es sustancial y notable por el tamaño de los colmillos. Los llamados 'toros de Ruaha', enormes elefantes viejos con marfil masivo, son legendarios entre los aficionados a la gran caza, aunque su número se ha reducido por la caza furtiva histórica. El parque también alberga una de las poblaciones de perros salvajes más significativas de África, y Ruaha está ampliamente considerado como el mejor lugar de Tanzania, posiblemente de África, para ver perros salvajes africanos." },
  { type: 'h2', text: 'La fauna de Ruaha' },
  { type: 'ul', items: [
    'León: densidad extraordinaria; grandes manadas con múltiples machos adultos; avistamientos muy fiables',
    'Perro salvaje africano: manadas de 10-30 individuos; mejor parque de Tanzania para encuentros con perros salvajes',
    'Leopardo: el terreno rocoso y el bosque ribereño crean un excelente hábitat; fiable con búsqueda paciente',
    'Guepardo: presente aunque menos común que en los parques de praderas abiertas',
    'Elefante: grandes toros con impresionantes colmillos; las manadas se congregan en el río en la estación seca',
    'Búfalo: grandes manadas a lo largo del Gran Río Ruaha en la estación seca',
    'Kudu: tanto el kudu mayor como el menor, poco comunes en los parques del norte de Tanzania',
    'Antílope sable: uno de los antílopes más hermosos de África; fiable en Ruaha',
    'Antílope ruano: otra especie poco común raramente vista al norte del Valle del Rift',
    'Cocodrilo e hipopótamo: masivas concentraciones en las pozas del Gran Río Ruaha',
  ]},
  { type: 'h2', text: 'El Gran Río Ruaha' },
  { type: 'p', text: 'El Gran Río Ruaha es la columna vertebral ecológica del parque. En la estación seca (junio-octubre), cuando las fuentes de agua circundantes se secan, el río se convierte en el único agua del parque y todas las especies del ecosistema convergen en él. Las excursiones matutinas a lo largo del río revelan grupos de hipopótamos, enormes cocodrilos, grupos familiares de elefantes bebiendo al amanecer y leones sobre presas a metros del agua. La concentración de vida a lo largo del río durante la estación seca rivaliza con cualquier cosa en el Serengueti.' },
  { type: 'p', text: 'Los safaris a pie a lo largo del río —realizados con un guardabosques armado— son una de las experiencias emblemáticas de Ruaha. A pie, siguiendo a una manada de perros salvajes o aproximándose a una manada de leones con un guardabosques experto, la escala del parque y la naturaleza salvaje de los animales adquieren una dimensión completamente diferente. La experiencia del safari a pie de Ruaha se considera una de las mejores de África Oriental precisamente porque la fauna está menos habituada y el entorno es genuinamente remoto.' },
  { type: 'h2', text: 'Cómo llegar a Ruaha' },
  { type: 'p', text: 'Ruaha está en el circuito sur de Tanzania, a una distancia significativa de los parques del Circuito Norte. No puedes combinar Ruaha y el Serengueti de forma eficiente en un itinerario de una semana. La mayoría de los visitantes de Ruaha vuelan: Coastal Aviation, Auric Air y otras aerolíneas de bush operan vuelos programados y chárter desde Dar es Salaam y Arusha hasta la pista de aterrizaje de Msembe dentro del parque. Los vuelos desde Dar es Salaam duran aproximadamente 60-75 minutos. Desde Arusha, el viaje suele implicar una conexión en Dar o un chárter directo.' },
  { type: 'tip', title: 'La mejor época para visitar Ruaha', text: 'La estación seca de junio a octubre es el momento principal para Ruaha, especialmente de julio a octubre cuando el Gran Río Ruaha concentra la fauna de todo el parque. La temporada húmeda (diciembre-abril) ve al parque transformarse: exuberante y verde, bueno para la avifauna y los animales recién nacidos, pero algunos caminos se vuelven intransitables y menos campamentos están abiertos.' },
  { type: 'h2', text: 'Combinar Ruaha con Nyerere' },
  { type: 'p', text: 'Ruaha se combina naturalmente con el Parque Nacional Nyerere (anteriormente Reserva de Caza Selous), una vasta naturaleza salvaje en el sur de Tanzania que ofrece safaris en barca por el río Rufiji, una experiencia no disponible en ningún lugar del Circuito Norte. Un itinerario del circuito sur que combine Ruaha (cuatro o cinco noches, safari terrestre y caminatas) con Nyerere (dos o tres noches, safari en barca y acampada volante) es uno de los itinerarios más completos y gratificantes de Tanzania.' },
  { type: 'callout', text: 'Ruaha es el safari de Tanzania del que los viajeros experimentados de África hablan en voz baja cuando quieren compartir un secreto. Es más difícil de alcanzar que el Serengueti, menos famoso y significativamente menos concurrido. Recompensa el esfuerzo con encuentros de fauna —cacerías de perros salvajes al amanecer, manadas de leones sobre presas en el río, toros de elefante al atardecer— que son tan dramáticos como cualquier cosa que produce el Circuito Norte, con una fracción del público.' },
],

'tanzania-vs-south-africa-safari': [
  { type: 'p', text: 'Tanzania y Sudáfrica son los dos destinos de safari más visitados de África, y son más diferentes entre sí de lo que la mayoría de los visitantes primerizos esperan. Comparten especies y el concepto de safari, pero ofrecen experiencias fundamentalmente distintas en términos de paisaje, fauna, infraestructura, cultura y lo que se siente estar en el bush. Elegir entre ellos es una de las preguntas más comunes en la planificación de viajes a África, y la respuesta honesta requiere mirar más allá de las afirmaciones del folleto de ambos.' },
  { type: 'h2', text: 'La fauna: la comparación fundamental' },
  { type: 'p', text: 'El argumento de Tanzania en cuanto a fauna descansa en tres cosas: la Gran Migración, la escala y la integridad del ecosistema. El ecosistema Serengueti-Mara es el sistema de fauna migratoria intacto más grande que queda en la Tierra, y ningún otro país africano tiene algo comparable. El movimiento anual de 1,5 millones de ñus y 500.000 cebras es un espectáculo que Tanzania posee absolutamente. Más allá de la migración, la pura densidad y variedad de fauna en los múltiples ecosistemas de Tanzania —desde los guepardos del Serengueti hasta los perros salvajes de Ruaha y los chimpancés de Mahale— no tiene igual.' },
  { type: 'p', text: "El argumento de Sudáfrica en cuanto a fauna descansa en el acceso y la gestión. El Parque Kruger tiene unos excelentes avistamientos de los Cinco Grandes, una infraestructura vial extremadamente bien mantenida y una red de reservas privadas de caza (Sabi Sand, Timbavati, Thornybush) adyacentes al Kruger donde los leopardos han sido tan completamente habituados durante décadas que los encuentros cercanos y prolongados son casi rutinarios. Sudáfrica también tiene la mayor densidad de reservas de caza privadas de África: opciones sin malaria como Madikwe, Waterberg y las reservas de los Cape Winelands la hacen accesible para familias con niños pequeños y viajeros preocupados por el riesgo de malaria." },
  { type: 'h2', text: 'La experiencia del safari: cómo se sienten de diferente' },
  { type: 'p', text: 'Un safari en Tanzania se siente como el África salvaje. Los parques son vastos, los caminos son accidentados, los campamentos están aislados y la fauna es genuinamente salvaje e impredecible. Las excursiones a menudo cubren cientos de kilómetros de naturaleza sin vallas. No hay semáforos entre Arusha y el Serengueti, no hay supermercados a un día de viaje de tu campamento, y el cielo nocturno —debido a la ausencia de contaminación lumínica— es extraordinario. Esta naturaleza salvaje es la esencia de lo que Tanzania ofrece.' },
  { type: 'p', text: 'Un safari en Sudáfrica —especialmente las reservas privadas— se siente más pulido. Las excursiones nocturnas son estándar, la conducción fuera de carretera es rutinaria y los guías en Sabi Sand son de los más conocedores de África precisamente porque pasan toda su carrera rastreando a los mismos individuos en una reserva relativamente pequeña. La infraestructura es de primera clase. Puedes volar a Johannesburgo en un vuelo con escala, conducir tres horas hasta la reserva y estar de excursión esa misma tarde. La logística es fácil de una manera que Tanzania requiere planificación.' },
  { type: 'h2', text: 'Diferencias clave de un vistazo' },
  { type: 'table', headers: ['Factor', 'Tanzania', 'Sudáfrica'], rows: [
    ['Gran Migración', 'Sí, exclusivamente', 'No'],
    ['Riesgo de malaria', 'Moderado a alto en zonas de safari', 'Opciones sin malaria disponibles'],
    ['Conducción fuera de carretera', 'Solo concesiones privadas', 'Estándar en reservas privadas'],
    ['Excursiones nocturnas', 'Solo zonas privadas', 'Estándar en reservas privadas'],
    ['Infraestructura', 'Básica a lujosa; caminos accidentados', 'Excelente; logística fácil'],
    ['Avistamiento de leopardos', 'Bueno pero animales tímidos', 'Sobresaliente en Sabi Sand'],
    ['Perro salvaje', 'Excelente (Ruaha, Nyerere)', 'Bueno (Kruger y reservas)'],
    ['Combinación de playa', 'Zanzíbar (sobresaliente)', 'Ruta del Jardín, Ciudad del Cabo'],
    ['Coste del primer safari', 'Ligeramente más alto en general', 'La gama media es muy competitiva'],
    ['Escala del ecosistema', 'Vasto, salvaje, sin vallas', 'Reservas valladas; menor escala'],
  ]},
  { type: 'h2', text: '¿Cuál es mejor para un primer safari?' },
  { type: 'p', text: 'Para un visitante primerizo de África que elige entre Tanzania y Sudáfrica, la decisión a menudo se reduce a dos factores: ¿Quieres ver la Gran Migración? ¿Y qué importancia tiene viajar sin malaria? Si la Migración está en tu lista —y debería estarlo— Tanzania es la única respuesta. Si viajas con niños pequeños y quieres opciones sin malaria con excelentes avistamientos de los Cinco Grandes, la Reserva Madikwe o el Waterberg de Sudáfrica es un primer safari excelente que es logísticamente más sencillo y médicamente de menor riesgo.' },
  { type: 'p', text: 'Tanzania recompensa a los visitantes que aceptan una experiencia africana más salvaje, más remota y más auténtica. Sudáfrica recompensa a los visitantes que quieren el safari más consistente, más fácilmente organizado y con mejor infraestructura. Ambos son destinos extraordinarios: la elección se trata genuinamente de personalidad y prioridades, no de calidad.' },
  { type: 'tip', title: 'La solución de dos países', text: 'Muchos viajeros habituales de África combinan ambos países: Tanzania para la Migración y la playa de Zanzíbar, Sudáfrica para las excursiones nocturnas de Sabi Sand, Ciudad del Cabo y la Ruta del Jardín. Dos semanas en ambos países captura lo mejor de la fauna africana y ofrece dos experiencias culturales y paisajísticas completamente distintas.' },
  { type: 'callout', text: 'Tanzania es el África salvaje tal como se pretendía experimentarla: vasta, impredecible y humillante en su escala. Sudáfrica es el turismo de fauna refinado hasta convertirlo en una ciencia: consistente, accesible y pulido a un alto estándar. Ninguno de los dos es un compromiso. Ambos merecen estar en tu itinerario por África, en diferentes momentos de tu vida de safari.' },
],

'mountain-biking-arusha': [
  { type: 'p', text: 'El Parque Nacional de Arusha es el destino de aventura más subestimado de Tanzania. Mientras la mayoría de los visitantes lo atraviesan en pocas horas de camino hacia los parques del Circuito Norte, el parque esconde algo que pocos itinerarios de safari incluyen jamás: una excelente red de senderos de mountain bike a través de bosque montano, páramo abierto y el borde del Cráter Ngurdoto, una de las características geológicas más hermosas pero más pasadas por alto de Tanzania.' },
  { type: 'h2', text: '¿Por qué hacer mountain bike en el Parque Nacional de Arusha?' },
  { type: 'p', text: 'El Parque Nacional de Arusha se asienta en la base del Monte Meru —la segunda montaña más alta de Tanzania— y asciende a través de una dramática secuencia de hábitats: sabana de acacias en las tierras bajas, bosque de Cussonia, bosque de podocarpus y el páramo alpino en las laderas superiores de Meru. La diversidad de terreno dentro de un solo parque lo convierte en uno de los mejores entornos de mountain bike de África Oriental, y la combinación de encuentros con fauna y desafío físico sobre dos ruedas es genuinamente difícil de replicar en cualquier otro lugar del continente.' },
  { type: 'p', text: 'A diferencia de las excursiones en vehículo, el mountain bike en el parque te permite moverte por el paisaje a un ritmo diferente: lo suficientemente rápido para cubrir terreno, lo suficientemente lento para escuchar a los colobos llamando en lo alto, notar las huellas frescas de elefante a través del camino, o detenerte en un mirador sobre el lago Momela sin el ruido y el confinamiento de un vehículo. Es una experiencia fundamentalmente más íntima del bush.' },
  { type: 'h2', text: 'Qué esperar en los senderos' },
  { type: 'p', text: 'Los senderos de ciclismo en el Parque Nacional de Arusha varían desde pistas forestales suaves hasta sendero simple más técnico a través de la zona montana. Los ciclistas principiantes e intermedios están bien servidos por el circuito forestal principal, que serpentea entre imponentes podocarpus, bambúes y claros abiertos donde los colobos blanco y negro están prácticamente garantizados. Los ciclistas más confiados pueden subir más alto hacia el borde del Cráter Ngurdoto o por el bucle de los Lagos Momela, donde los flamencos y las aves acuáticas llenan las aguas alcalinas.' },
  { type: 'p', text: 'Los encuentros con fauna son constantes en cada sendero. Las jirafas se yerguen en el bosque abierto, aparentemente sin perturbarse por los ciclistas. Los búfalos pastan en el cuenco del cráter más abajo. Las familias de jabalíes cruzan el camino a toda velocidad. El parque también alberga una sana población de leopardos: raramente vistos pero a veces detectados por los guías experimentados que saben dónde buscar y qué señales leer.' },
  { type: 'image', src: '/images/gallery/IMG-20260610-WA0079.webp', alt: 'Cyclists on a forest trail in Arusha National Park with tall trees overhead', caption: 'The montane forest trails offer shade, wildlife, and dramatic scenery in every direction.' },
  { type: 'h2', text: 'Logística e información práctica' },
  { type: 'ul', items: [
    'Las bicicletas de montaña y los cascos son proporcionados por los operadores locales; lleva tus propios guantes y pantalones acolchados si es posible',
    'Todas las excursiones requieren escolta de un guardabosques armado: estándar en todos los parques nacionales de Tanzania para actividades a pie o en bicicleta',
    'Hay circuitos de medio día y día completo disponibles; el circuito del borde del Ngurdoto de todo el día es el más gratificante',
    'Mejores meses: junio-octubre (estación seca) para los senderos más despejados y los mejores avistamientos de fauna; los senderos de marzo-mayo pueden ser muy embarrados',
    'Forma física mínima: un nivel base razonable de forma física ciclista; el circuito forestal es apto para no especialistas',
    'Nota sobre la altitud: el parque alcanza los 2.500 m en el Cráter de Meru: puede sentirse algo de falta de aliento si se llega desde baja altitud',
  ]},
  { type: 'h2', text: 'Combinar el ciclismo con un safari' },
  { type: 'p', text: 'El ciclismo en el Parque Nacional de Arusha funciona perfectamente como excursión de un día desde la ciudad de Arusha antes o después de tu safari principal por el Circuito Norte. También se puede combinar con una excursión matutina en vehículo por el parque: ciclismo por el bosque por la mañana, luego conducción por la sección de los Lagos Momela por la tarde. El parque es lo suficientemente pequeño como para que ambas actividades caben cómodamente en un solo día. Alternativamente, el ciclismo se puede combinar con una caminata por el Monte Meru para dos días completos de aventura activa antes de que comience tu safari.' },
  { type: 'tip', title: 'Reserva con un operador local', text: 'Varios operadores de aventura con sede en Arusha ofrecen circuitos guiados de mountain bike en el parque. Se encargan de los permisos de TANAPA, proporcionan la escolta del guardabosques y suministran las bicicletas. Reserva con al menos 24 horas de antelación: los permisos se expiden en la entrada y algunos circuitos requieren salidas tempranas para evitar el calor.' },
  { type: 'callout', text: 'El mountain bike en el Parque Nacional de Arusha es una de esas experiencias que los viajeros descubren por casualidad y recuerdan durante años. Si tienes aunque sea medio día en Arusha antes o después de tu safari, cambia una excursión en vehículo por un paseo en bicicleta por el bosque: te encontrarás con la misma fauna, de una manera completamente diferente.' },
],

'zanzibar-experience': [
  { type: 'p', text: 'Zanzíbar es un nombre que tiene peso. Ha sido una isla de especias, un centro del comercio de esclavos, un sultanato árabe, un protectorado británico y uno de los crisoles culturales más distintivos del Océano Índico. Hoy, la mayoría de los visitantes la conocen como destino de playa —y las playas son extraordinarias—, pero reducir Zanzíbar a arena blanca y agua turquesa es como visitar Estambul por su clima. Hay mucho más que experimentar aquí de lo que solo los complejos turísticos revelan.' },
  { type: 'h2', text: 'Stone Town: el corazón de Zanzíbar' },
  { type: 'p', text: 'Stone Town es el barrio antiguo de la Ciudad de Zanzíbar, Patrimonio de la Humanidad de la UNESCO y uno de los entornos urbanos más arquitectónica y culturalmente densos de África Oriental. La ciudad creció a partir de un asentamiento comercial árabe en el siglo XIX, cuando Zanzíbar era el centro del comercio de especias y esclavos del Océano Índico. El sultán de Omán trasladó su corte aquí en 1840, y la arquitectura que siguió —casas persas con patios interiores, casas de ciudad árabes con balcones salientes, edificios comerciales de piedra de coral— sigue definiendo el paisaje urbano hoy en día.' },
  { type: 'p', text: 'Pasear por Stone Town sin mapa es el enfoque correcto. Las estrechas calles, demasiado pequeñas para los vehículos, se abren inesperadamente a mercados de especias, cafés en patios interiores, minaretes de mezquita y las ruinas ocasionales de una antigua subasta de esclavos. Cada puerta de madera tallada que pasas cuenta una historia: cuanto más grande y elaborada es la puerta, más rico y socialmente poderoso era la familia que la encargó. Las puertas con espigas de latón hacia afuera son una adaptación zanzibari de una tradición india, originalmente diseñadas para evitar que los elefantes de guerra las embastiesen, adoptadas aquí como puro símbolo de estatus.' },
  { type: 'image', src: '/images/gallery/stone-town.webp', alt: 'Historic carved wooden door in Stone Town Zanzibar', caption: "Stone Town's famous carved doors are a physical record of the island's layered cultural history." },
  { type: 'h2', text: 'La experiencia de la granja de especias' },
  { type: 'p', text: 'Zanzíbar ganó su nombre histórico como Isla de las Especias de las plantaciones de clavo introducidas por los comerciantes árabes a principios del siglo XIX. En su apogeo, Zanzíbar suministraba la mayoría de los clavos del mundo. Hoy las plantaciones cubren partes del interior de la isla, y un tour por una granja de especias, aunque es una actividad turística bien trillada, sigue siendo una de las experiencias más sensoriales disponibles en la isla.' },
  { type: 'p', text: 'Un buen tour de especias te lleva a través de una granja en activo donde un guía te conduce a las plantas vivas y explica lo que estás viendo: el árbol del clavo con sus hojas de color verde oscuro y pequeños capullos de flores que se secan hasta convertirse en el clavo familiar; la orquídea de vainilla trepando por un poste de soporte; el árbol de la canela cuya corteza se pela en aromáticas tiras; la enredadera de pimienta negra que se entreteje por el dosel. Todo lo que hueles y saboreas aquí conecta directamente con una historia comercial global que se remonta a siglos.' },
  { type: 'h2', text: 'Isla Prisión y las tortugas gigantes' },
  { type: 'p', text: 'A un corto viaje en barca desde Stone Town, Isla Prisión (Isla Changuu) fue construida por los británicos en 1893 como instalación de cuarentena y posteriormente utilizada como centro de detención. Hoy es famosa por su colonia de tortugas gigantes de Aldabra, regaladas a la isla desde las Seychelles en 1919. Algunos de estos individuos tienen más de 100 años: criaturas enormes y de movimiento lento que permiten a los visitantes acercarse a ellas, alimentarlas con hierba y posar para fotografías de una manera que sería imposible en cualquier lugar menos gestionado.' },
  { type: 'image', src: '/images/gallery/Prison-island1.webp', alt: 'Giant Aldabra tortoise at Prison Island Zanzibar', caption: 'Some of the Prison Island tortoises are over 100 years old — and completely unfazed by visitors.' },
  { type: 'h2', text: 'El bosque de Jozani y el mono colobo rojo' },
  { type: 'p', text: 'El Parque Nacional de Jozani Chwaka Bay protege un parche remanente de bosque de aguas subterráneas en el interior de la isla, y la última población significativa del mono colobo rojo de Zanzíbar, uno de los primates más raros del mundo. Estos monos de color cobre y negro son endémicos de Zanzíbar y no se encuentran en ningún otro lugar de la Tierra. Los grupos habituados se mueven por el dosel del bosque directamente encima de la pasarela elevada, ofreciendo vistas excelentes y cercanas sin ningún esfuerzo.' },
  { type: 'image', src: '/images/gallery/Jozani-forest.webp', alt: 'Zanzibar red colobus monkey in Jozani Forest with lush green backdrop', caption: 'The Zanzibar red colobus is found only on this island — and Jozani Forest is the best place to see them.' },
  { type: 'h2', text: 'Las playas' },
  { type: 'p', text: 'Después de toda la cultura y la historia, las playas de Zanzíbar realmente cumplen las expectativas. El agua del Océano Índico es cálida todo el año, la arena es coral blanco fino y los sistemas de arrecifes —especialmente alrededor del Atolón Mnemba en el noreste y el Parque Marino Isla Chumbe en el suroeste— ofrecen el snorkel más accesible de África. Nungwi en el norte y Kendwa, justo al sur, tienen la mejor natación con cualquier marea (la mayoría de las playas de la costa este se vuelven muy superficiales con la marea baja). Paje en la costa sureste es la capital del kitesurf del Océano Índico.' },
  { type: 'ul', items: [
    'Mejores playas para nadar: Nungwi y Kendwa (costa norte)',
    'Mejor para el kitesurf: Paje y Jambiani (costa sureste)',
    'Mejor para el snorkel: Atolón Mnemba (noreste)',
    'Mejor para la historia: Kizimkazi (sur): natación con delfines y mezquita antigua',
    'La más desarrollada con más restaurantes: Nungwi',
  ]},
  { type: 'callout', text: 'Las playas y la cultura juntas —no por separado— son lo que hace excepcional a Zanzíbar. Un día en Stone Town seguido de tres días en la playa te da dos Zanzíbares completamente diferentes. Ambos merecen la pena.' },
],

'the-maasai-tribe': [
  { type: 'p', text: 'Los maasai son uno de los pueblos indígenas más fotografiados, más escritos y más reconocidos del mundo, y sin embargo la mayoría de los visitantes de safari abandonan Tanzania sabiendo muy poco más sobre ellos que la tela roja y los saltos. Esto se debe en parte a la condensada visita al boma que incluye la mayoría de los itinerarios: una parada de 45 minutos en un asentamiento comunitario, una demostración de salto, una exhibición de hacer fuego y un vistazo al mercado artesanal. Es auténtico en algunos aspectos y una actuación en otros, y rara vez rasca la superficie de una cultura que ha resistido la asimilación durante siglos en uno de los paisajes más disputados y ricos en fauna salvaje de la Tierra.' },
  { type: 'h2', text: '¿Quiénes son los maasai?' },
  { type: 'p', text: 'Los maasai son un pueblo nilótico que emigró hacia el sur desde la región del Valle del Nilo alrededor del siglo XV, estableciéndose finalmente por lo que hoy es el sur de Kenia y el norte de Tanzania. En su apogeo en el siglo XIX, el territorio maasai se extendía desde lo que hoy es el centro de Kenia hasta el Gran Valle del Rift en Tanzania, un vasto dominio pastoral sostenido por guerreros cuya reputación los hacía temidos en toda África Oriental. Los colonizadores europeos, que llegaron a finales del siglo XIX, encontraron a los maasai como el único pueblo de la región que no cedía fácilmente, y los acuerdos coloniales de tierras que siguieron —confinando a las comunidades maasai en reservas específicas— siguen siendo controvertidos hoy en día.' },
  { type: 'p', text: 'Los maasai son pastores semi-nómadas. Su riqueza se mide en ganado: el estatus social de un hombre, su elegibilidad para el matrimonio y su capacidad para funcionar como miembro plenamente adulto de la comunidad están todos vinculados al tamaño y la salud de su rebaño. El ganado no es solo un activo; es una divisa espiritual, una historia familiar y un contrato social. Los maasai comen tradicionalmente una dieta de carne, sangre y leche, una dieta rica en proteínas que sustentó su cultura guerrera a través de siglos de conflicto y variabilidad ambiental.' },
  { type: 'h2', text: 'El sistema de clases de edad' },
  { type: 'p', text: 'La sociedad maasai se organiza en torno a un sistema de clases de edad: cohortes de hombres que atraviesan etapas de vida definidas juntos. Los chicos del mismo grupo de edad son circuncidados juntos, entran juntos en la clase de guerrero (moran), se retiran juntos de la guerrería y avanzan juntos al estatus de anciano. Estos lazos, forjados en la experiencia compartida de cada etapa, crean una cohesión social extraordinariamente estrecha dentro de cada grupo de edad.' },
  { type: 'p', text: 'Los moran —guerreros jóvenes normalmente de entre 15 y 30 años— son los miembros más visibles y más fotografiados de la sociedad maasai. Llevan la shuka roja (tela), portan lanzas, trenzan y tiñen su largo cabello con ocre, y son la cohorte responsable de proteger el ganado de la comunidad de los depredadores y las incursiones. Históricamente, un joven demostraba su valía como guerrero matando a un león solo con una lanza, una práctica ahora ilegal y cada vez más rara, aunque sigue siendo un punto de referencia cultural y de orgullo.' },
  { type: 'h2', text: 'Coexistir con la fauna salvaje' },
  { type: 'p', text: 'El aspecto más notable de la cultura maasai, desde una perspectiva de conservación, es la tradición de coexistencia con la fauna salvaje a una escala que no tiene casi paralelo en el mundo. Las comunidades maasai han permitido históricamente que la fauna salvaje se mueva por sus tierras de pastoreo sin persecución sistemática. Los leones, los leopardos y los elefantes comparten territorio con el ganado maasai en enormes áreas del ecosistema Serengueti-Mara y la cuenca de Amboseli. Esta coexistencia no siempre es cómoda —el ganado es matado por depredadores y la tensión entre la economía de la conservación y los medios de vida pastorales es real y continua—, pero la tolerancia a nivel de paisaje ha sido fundamental para la supervivencia de las grandes poblaciones de fauna salvaje de África Oriental.' },
  { type: 'p', text: 'Esta relación se está formalizando hoy a través de los conservancies comunitarios, donde los propietarios de tierras maasai reciben pagos directos por permitir que la fauna salvaje use sus tierras. En el ecosistema Amboseli-Tsavo en Kenia y en el Área de Conservación del Ngorongoro en Tanzania, las comunidades maasai son actores activos en el turismo de fauna salvaje, recibiendo tarifas por noche de alojamiento, empleo y pagos de conservación que hacen que el león en su tierra valga más vivo que el área equivalente de tierras de cultivo.' },
  { type: 'h2', text: 'Cómo es realmente una visita al boma' },
  { type: 'p', text: 'Un boma es un asentamiento maasai: un asentamiento circular de pequeñas casas enlucidas de barro dispuestas alrededor de un recinto central de ganado, protegido por una cerca de espino. La visita al boma incluida en la mayoría de los itinerarios de safari en Tanzania ofrece una ventana genuina a este mundo doméstico, aunque también es una transacción comercial.' },
  { type: 'p', text: 'En una buena visita al boma, verás la estructura del asentamiento: la disposición de las casas, la relación entre el recinto del ganado y las viviendas, la manera en que el asentamiento gestiona el movimiento de los animales por la noche. Verás la fabricación de fuego tradicional (palos de fricción), escucharás las canciones específicas de los grupos de edad y las ceremonias, y presenciarás una demostración de la danza de salto adumu, una prueba atlética del guerrero y una exhibición social. Las mujeres te mostrarán sus abalorios, que son un lenguaje visual tan complejo como cualquier tradición textil africana: cada combinación de color y patrón comunica información específica sobre la edad, el estado civil y la comunidad de quien lo lleva.' },
  { type: 'tip', title: 'Elegir una visita genuina al boma', text: 'Hay una diferencia significativa entre un boma altamente comercializado en las rutas turísticas principales y una visita comunitaria organizada a través de una empresa de propiedad maasai o un operador local de confianza. Pregunta a tu empresa de safari si la visita al boma implica un compromiso comunitario genuino o una actuación para autobuses turísticos. Esta última no carece de valor, pero no es la misma experiencia.' },
  { type: 'h2', text: 'Los maasai hoy' },
  { type: 'p', text: 'La historia contemporánea de los maasai es una de negociación cultural bajo presión. El acceso a la educación, los teléfonos móviles y el empleo asalariado ha atraído a los maasai más jóvenes a las economías tanzana y keniana más amplias, mientras que la presión sobre las tierras de la expansión agrícola, los límites de la conservación y el desarrollo de la infraestructura sigue reduciendo el territorio pastoral. La tensión entre preservar la identidad cultural y acceder a las oportunidades de la economía moderna se siente agudamente en cada comunidad maasai.' },
  { type: 'p', text: 'Muchos maasai están navegando esta tensión de maneras notables. Las empresas turísticas de propiedad maasai —conservancies, centros culturales, programas de formación de guías— están creando vías económicas que vinculan directamente la preservación cultural con los ingresos. Un guía maasai en el ecosistema Amboseli que habla inglés con fluidez, puede nombrar cada pájaro por su nombre en latín y en maa, y también puede explicar la estructura de gobernanza de los derechos de tierra de su familia no es una contradicción de su cultura: es el producto de su extraordinaria adaptabilidad.' },
  { type: 'callout', text: 'La shuka roja y el guerrero saltador se han convertido en una taquigrafía visual para la naturaleza salvaje de África Oriental en todo el mundo. Pero cuanto más tiempo pasas con las comunidades maasai —a través de un compromiso cultural genuino en lugar de una visita escenificada—, más complejo, ingenioso y profundamente arraigado en la tierra se revela ser este pueblo. Su presencia en el paisaje no es una curiosidad al margen de tu safari; es parte de lo que hace funcionar el ecosistema.' },
],

}

export function getArticleContent(slug: string): SectionType[] | undefined {
  return articles[slug]
}
